INSERT INTO public.photos VALUES (25669, 'Casa de Zaporta 1844', 'Dibujo de Jenaro Pâ”œآ®rez de Villaamil incluido en la obra "Espaâ”œâ–’a artâ”œآ،stica y monumental vistas y descripciâ”œâ”‚n de los sitios y monumentos mâ”œأ­s notables de Espaâ”œâ–’a". Ademâ”œأ­s de colaborar con dibujos, Pâ”œآ®rez de "Villa-Amil" (sic) era el director de la obra, cuyos textos fueron redactados por Patricio de la Escosura, y su ediciâ”œâ”‚n se realizâ”œâ”‚ en Parâ”œآ،s por Albert Hauser entre 1842 y 1850. En la imagen, dibujo del "Patio de la casa de la Infanta en Zaragoza", antigua casa de Zaporta sita en la calle Alta de San Pedro, en una de sus caâ”œâ”‚ticas etapas. Fuente visual: ddd.uab.cat/', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24863075321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24863075321.webp', 'https://www.flickr.com/photos/zaragozaantigua/24863075321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25670, 'Calle de la Verâ”œâ”‚nica 1966', 'Captura desde la calle de la Verâ”œâ”‚nica de la antigua manzana de viviendas delimitada por las calles Don Jaime I (al fondo), Verâ”œâ”‚nica (derecha), y Valentâ”œآ،n Zabala (izquierda), cuando habâ”œآ،an comenzado las obras preparativas (maderos de las ventanas), previas a su derribo integral. A la izquierda, el edificio del Teatro Principal, fuera de plano y, en el suelo, el tendido viario del bucle que efectuaba la lâ”œآ،nea 13 "San Josâ”œآ®" , para volver a subir hacia esa direcciâ”œâ”‚n, desde la calle Eusebio Blasco. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Registro ES. 50297. AM 04.01.02.11 38137', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65234600, -0.87917300, '0101000020E6100000B2D6506A2F22ECBF95D6DF1280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26621199525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26621199525.webp', 'https://www.flickr.com/photos/zaragozaantigua/26621199525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25674, 'Calle Don Jaime aâ”œâ–’os 20', 'Esquina de la calle de Don Jaime I con la de los Estâ”œآ®banes (izquierda). Allâ”œآ، se situaba el establecimiento Rived y Châ”œâ”‚liz, de los socios Miguel Rived y Antonio Châ”œâ”‚liz, fundado en 1901 y dedicado a laboratorio farmacâ”œآ®utico y fotogrâ”œأ­fico. En 1930, Châ”œâ”‚liz se desvinculâ”œâ”‚ del negocio. Fuente: www.facebook.com/photo.php?fbid=1330866140308827&set=...', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65281400, -0.87912200, '0101000020E61000002A36E675C421ECBF7B2FBE688FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595412102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595412102.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595412102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25675, 'Calle Estâ”œآ®banes 1925', '"San Gil. Zaragoza". Acuarela de Salvador de Azpiazu, 1925. Vista de la torre de la iglesia de San Gil desde la calle de los Estâ”œآ®banes. Le acompaâ”œâ–’a otro pequeâ”œâ–’o dibujo con personajes tâ”œآ،picos ante una casa palaciega. Fuente visual: AMZ.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65310300, -0.87967000, '0101000020E6100000D8B628B34126ECBFB2F50CE198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126588186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126588186.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126588186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25677, 'Calle Alta de San Pedro 1844', '"Patio de la Infanta", en la antigua casa de Zaporta. Al fondo, a la derecha, las monumentales escaleras de acceso a las plantas superiores. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•‌edades y vistas pintorescas en lâ”œأ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œآ® Marâ”œآ،a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.65291000, -0.87800700, '0101000020E61000001E17D522A218ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34829405196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34829405196.webp', 'https://www.flickr.com/photos/zaragozaantigua/34829405196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25680, 'Calle de Don Jaime I 1964', 'Cortejo oficial y tradicional encabezado, sobre mula blanca, del tradicionalista Pedro Cantero Cuadrado durante la toma de posesiâ”œâ”‚n como nuevo arzobispo de Zaragoza, el dâ”œآ،a 16 de julio de 1964, bajo un sofocante calor. La imagen se ha tomado en la calle de Don Jaime I, en el tramo desde las calles de San Jorge y Casto Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez, al fondo, hasta la plaza de Ariâ”œâ–’o, a espaldas del fotâ”œâ”‚grafo. Tras el arzobispo, la comitiva figura encabezada, a caballo, por el alcalde Luis Gâ”œâ”‚mez Laguna y el teniente de alcalde Gregorio Sâ”œأ­nchez Morales, los gobernadores civil y militar, y demâ”œأ­s autoridades, incluyendo una representaciâ”œâ”‚n de Carriâ”œâ”‚n de los Condes, pueblo natal del nuevo responsable de la diâ”œâ”‚cesis zaragozana. A ambos lados de la calle, gente asomada a los balcones de edificios que aâ”œâ–’os despuâ”œآ®s serâ”œآ،an, los mâ”œأ­s, derribados y sustituidos, sobre todo en el lado de la izquierda, por modernos bloques. Al fondo, el inmueble del nâ”¬â•‘ 18, diseâ”œâ–’ado por Teodoro Râ”œآ،os Balaguer en 1935 como sede de la Câ”œأ­mara Oficial de Comercio e Industria. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65337200, -0.87839000, '0101000020E610000024456458C51BECBFA10F96B1A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45719418965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45719418965.webp', 'https://www.flickr.com/photos/zaragozaantigua/45719418965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25868, 'Teatro Principal 1922', 'Imagen capturada desde el escenario del Teatro Principal y orientada hacia el pâ”œâ•‘blico asistente a la funciâ”œâ”‚n benâ”œآ®fica organizada por los asilados del Hospicio Provincial, patrocinada por la Diputaciâ”œâ”‚n Provincial y celebrada el 29 de marzo de 1922 con el desinteresado concurso de las compaâ”œâ–’â”œآ،as de los teatros Principal, Circo y Parisiana. En la imagen, el patio de butacas aparece prâ”œأ­cticamente lleno de los asilados del Hospicio, mientras la escala social ya es otra en los palcos de autoridades, como es normal.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.65208000, -0.87926000, '0101000020E61000006DCA15DEE522ECBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50025722141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50025722141.webp', 'https://www.flickr.com/photos/zaragozaantigua/50025722141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25870, 'Teatro Principal 1912', 'Imagen capturada en el interior del Teatro Principal durante el ensayo de una escena del tercer acto del "vaudeville" o comedia titulada "Petit Cafâ”œآ®", obra de Tristâ”œأ­n Bernard adaptada por Juan Josâ”œآ® Cadenas y mâ”œâ•‘sica del maestro Licâ”œâ”‚, producida por Pepe Cadenas y representada por la Compaâ”œâ–’â”œآ،a Palma-Reig, cuyos titulares eran la actriz Enriqueta Palma y el actor Luis Reig. Esta obra era la de mayor â”œآ®xito de la temporada, de forma que algâ”œâ•‘n periâ”œâ”‚dico considerâ”œâ”‚ que mâ”œأ­s que "Petit Cafâ”œآ®", este serâ”œآ،a el "Cafâ”œآ® Ambos Mundos" del Teatro Principal en el sentido de que atraerâ”œآ،a a mucha parroquia. Esta fue una muy buena noticia para este coliseo municipal, que desde principios de siglo venâ”œآ،a viviendo unos aâ”œâ–’os muy complicados, con constantes cambios en los arriendos concertados con diversos empresarios teatrales y poca asistencia de pâ”œâ•‘blico. En setiembre de 1912 el arriendo recayâ”œâ”‚ en la razâ”œâ”‚n social de Juan Bautista Simâ”œâ”‚n, que conociâ”œâ”‚ un arranque de temporada muy malo tras una ruinosa campaâ”œâ–’a durante las fiestas del Pilar. La imagen muestra el escenario y el patio de butacas con el aspecto tras la importante reforma proyectada por el arquitecto Ricardo Magdalena a finales del siglo XIX, destacando el espacio destinado a la orquesta.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65208000, -0.87926000, '0101000020E61000006DCA15DEE522ECBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457794516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457794516.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457794516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25896, 'Calle de la Verâ”œâ”‚nica 1970', 'Trolebâ”œâ•‘s de la lâ”œآ،nea "Gâ”œأ­llego" en su Terminal de la calle de la Verâ”œâ”‚nica, en 1970. Al fondo a la izquierda, las traseras de la iglesia del Sagrado Corazâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=10203016137152960&set...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65202700, -0.87864400, '0101000020E6100000B4739A05DA1DECBFF38DE89E75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085612780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085612780.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085612780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23290, 'Calle de Goya 1960', 'Imagen de la que fuera parte de la antigua y larguâ”œآ،sima calle de Contamina hasta que el bisturâ”œآ، urbanâ”œآ،stico la seccionâ”œâ”‚ en dos cuando fue abierta la nueva calle de Alfonso I. Asâ”œآ،, el tramo entre el Temple y la nueva Alfonso I, conservâ”œâ”‚ su nombre, mientras que el tramo desde Alfonso I, y hasta la calle de Santa Cruz, recibiâ”œâ”‚ el nombre de "Goya". Ese serâ”œآ،a su nombre durante casi un siglo, hasta que el cubrimiento del tramo urbano de las vâ”œآ،as del ferrocarril a Barcelona, hizo que el Ayuntamiento le transfiriera el nombre, elevado a la categorâ”œآ،a de "avenida". A esta callecita del casco antiguo se le otorgâ”œâ”‚, entonces, el nombre de otro pintor: Jusepe Martâ”œآ،nez, el principal pintor del barroco zaragozano. En la imagen, calle de Goya poco antes de ser redenominada "Jusepe Martâ”œآ،nez", desde su confluencia con la calle de Santa Cruz. En primer plano, el antiguo mojâ”œâ”‚n de piedra para impedir el paso a vehâ”œآ،culos. Al fondo, la calle Alfonso, y un poco antes, hacia la izquierda, la calle de las Vâ”œآ،rgenes, pues allâ”œآ، estuvo el antiguo "Real Colegio de las Vâ”œآ،rgenes", o de "Nâ”¬آ¬ Sâ”¬آ¬ del Socorro". Fuente visual: amable aportaciâ”œâ”‚n del Archivo personal de Pablo Valdâ”œآ®s.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65399600, -0.87909900, '0101000020E61000001F48DE399421ECBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638170711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638170711.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638170711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25199, 'P.â”¬â•‘ de la Independencia 1933', 'Plano del proyecto de prolongaciâ”œâ”‚n del paseo de la Independencia realizado por el arquitecto municipal Miguel â”œأ¼ngel Navarro. Tras el proyecto de 1930 de reforma interior urbana de los arquitectos Zuazo y Derqui, que contemplaba una prolongaciâ”œâ”‚n del paseo denominada "mâ”œأ­xima", por la anchura de 25 metros prevista para el nuevo vial resultante hasta el paseo del Ebro, esta nueva propuesta de 1933 preveâ”œآ،a una anchura de 20 metros hasta la calle del Pilar, donde confluirâ”œآ،a con una nueva avenida de uniâ”œâ”‚n de las plazas de las catedrales. En la imagen, comparativa de planos entre la situaciâ”œâ”‚n de partida, en la parte superior, y el resultado previsto tras la radical intervenciâ”œâ”‚n, en la parte inferior. Este proyecto quedâ”œâ”‚ en suspenso, y al aâ”œâ–’o siguiente Miguel â”œأ¼ngel Navarro realizarâ”œآ،a el no menos radical proyecto de apertura de la nueva calle de San Vicente de Paâ”œâ•‘l, que sâ”œآ، serâ”œآ،a realizado. A mediados de la dâ”œآ®cada de los aâ”œâ–’os sesenta, tras la conversiâ”œâ”‚n del paseo de la Independencia en una autopista para trâ”œأ­fico rodado, volviâ”œâ”‚ a ponerse encima de la mesa de trabajo el proyecto de su prolongaciâ”œâ”‚n, aunque tampoco pasarâ”œآ،a de las musas al teatro urbanâ”œآ،stico municipal. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65394200, -0.87911900, '0101000020E6100000E659492BBE21ECBF8CBD175FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36411653725.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36411653725.webp', 'https://www.flickr.com/photos/zaragozaantigua/36411653725/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25652, 'Tejados c.1925', 'Toma de tejados zaragozanos. En primer plano, edificio de la calle Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 17. Al fondo, el Pilar y La Seo. En el centro, la iglesia de Santa Cruz con el tejado de la Lonja detrâ”œأ­s. La imagen estâ”œأ­ tomada desde las oficinas de la Compaâ”œâ–’â”œآ،a Telefâ”œâ”‚nica en la calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 20, que fueron sustituidas por las del paseo de la Independencia en 1927. Fuente visual: Fundaciâ”œâ”‚n Telefâ”œâ”‚nica', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65381600, -0.87950000, '0101000020E6100000BE9F1A2FDD24ECBFFFCC203EB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15086705335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15086705335.webp', 'https://www.flickr.com/photos/zaragozaantigua/15086705335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25685, 'Calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 1926', 'Imagen capturada desde cierta altura en los tejados de la calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez y centrada en el singular remate del nâ”¬â•‘ 20 de ese vial, donde despuntaba la alâ”œأ­mbrica torrecilla del veterano Centro Telefâ”œâ”‚nico Urbano de Zaragoza. A la izquierda, la torre barroca y el cimborrio mudâ”œآ®jar de la catedral de la Seo. A la derecha, la torre de la iglesia de San Juan y San Pedro (antigua de San Juan el Viejo) junto a la torre de Santa Marâ”œآ،a Magdalena y su remate aâ”œâ–’adido en â”œآ®poca barroca. Estas instalaciones telefâ”œâ”‚nicas serâ”œآ،an desmanteladas con la entrada en funcionamiento de la nueva y moderna central sita en el paseo de la Independencia.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65385100, -0.87956000, '0101000020E610000013D55B035B25ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53029323105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53029323105.webp', 'https://www.flickr.com/photos/zaragozaantigua/53029323105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20905, 'La Escuela de las Vâ”œآ،rgenes 1531', 'La Escuela de las Vâ”œآ،rgenes, anâ”œâ”‚nimo, â”œâ”‚leo sobre tabla, c.1570. (DPZ). El cuadro reproduce la fundaciâ”œâ”‚n simbâ”œâ”‚lica del Colegio de las Vâ”œآ،rgenes de Zaragoza (1531), cuya primera sede estuvo en la Manterâ”œآ،a. En 1585 se trasladâ”œâ”‚ al palacio renacentista de la calle de las Botigas Fondas. En la escena, la propia Virgen Marâ”œآ،a se dirige a un grupo de muchachas con hâ”œأ­bito. Al fondo a la derecha, la primera rectora de la instituciâ”œâ”‚n, rezando ante un sagrario. Otras cuatro damas ilustres, detrâ”œأ­s del cuadro principal. Y a la izquierda, una puerta se abre a las calles de Zaragoza (tal vez la plaza de la Diputaciâ”œâ”‚n, junto a la Cuchillerâ”œآ،a), con algunos Diputados del Reino, patronos del Colegio. Fuente: ceres.mcu.es/', 1531, 1531, 1531, 'Siglo XIX', 'CENTRO', 41.65319300, -0.88316600, '0101000020E6100000670DDE57E542ECBFF27C06D49BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14924146817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14924146817.webp', 'https://www.flickr.com/photos/zaragozaantigua/14924146817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21008, 'Convento de Santa Fe c.1860', 'Convento de Santa Fe de Zaragoza. Valentâ”œآ،n Carderera. Lâ”œأ­piz y acuarela sobre papel, entre 1831 y 1880. Este "Ex monasterio de monjas" fue fundado en 1553 para acoger prostitutas, por lo que fue llamado "Convento de las Arrepentidas". Tras su uso como Museo, el edificio fue derribado en 1908, ampliâ”œأ­ndose asâ”œآ، la plaza Salamero. Fuente: "Viaje artâ”œآ،stico por Aragâ”œâ”‚n de Valentâ”œآ،n Carderera", Josâ”œآ® Marâ”œآ،a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano, 2013.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65251300, -0.88444200, '0101000020E6100000C0AE264F594DECBF809BC58B85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919266460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919266460.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919266460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21024, 'Puerta de la Audiencia 1860', '"Zaragoza: Porta de los Gigantes" Los mitolâ”œâ”‚gicos grandes personajes que flanquean el acceso, identificados habitualmente con Hâ”œآ®rcules y Teseo, presentan todavâ”œآ،a esos particulares tocados sobre la testa, que luego fueron eliminados, tal vez por una moda mâ”œأ­s severa y menos florida, durante la intervenciâ”œâ”‚n-restauraciâ”œâ”‚n dirigida por el arquitecto provincial Pedro Martâ”œآ،nez Sangrâ”œâ”‚s en 1862-64. Las dos figuras recostadas a ambos lados del frontâ”œâ”‚n cabecero, que parece ser que sustentaban el escudo de armas del conde de Morata, y el leâ”œâ”‚n del centro, tambiâ”œآ®n fueron retirados El de la derecha ya estâ”œأ­ casi descabezado. Fuente visual: Charles Clifford, en The Metropolitan Museum of Art', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65376200, -0.88344500, '0101000020E61000003012DA722E45ECBF0CAF2479AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21974069784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21974069784.webp', 'https://www.flickr.com/photos/zaragozaantigua/21974069784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21059, 'Convento de Santa Fe 1878', 'Fotografâ”œآ،a del claustro del desaparecido convento de Santa Fe, en la plaza del mismo nombre (actual de Salamero), en su â”œآ®poca como Museo Provincial de Zaragoza y Academia de Bellas Artes (entre 1848 y 1896). Pueden verse las obras artâ”œآ،sticas expuestas en la galerâ”œآ،a superior, abierta al aire libre. En el extremo del rincâ”œâ”‚n del claustro asoma el piso superior del torretâ”œâ”‚n de ladrillo renacentista del ex-convento.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65233400, -0.88381900, '0101000020E610000069AB92C83E48ECBFD10836AE7FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866310765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866310765.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866310765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21093, 'La Audiencia c.1880', 'Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n. Anselmo Coyne (ca. 1880), Palacio de la Audiencia.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65381900, -0.88342800, '0101000020E6100000ADDC0BCC0A45ECBF70404B57B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14690851640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14690851640.webp', 'https://www.flickr.com/photos/zaragozaantigua/14690851640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21839, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1931', 'Imagen del antiguo nâ”¬â•‘ 17 del paseo de Ruiseâ”œâ–’ores, que fuera uno de los originales seis hotelitos proyectados por Manuel Isasi Isasmendi de este perifâ”œآ®rico paseo (adquirido por Sebastiâ”œأ­n Rodrâ”œآ،guez), ya habilitado temporalmente como "La Casa del Niâ”œâ–’o", un instituto nipiolâ”œâ”‚gico o internado para atenciâ”œâ”‚n y cuidado de la salud de niâ”œâ–’os impulsado por el doctor Fernando Cuenca. Este hotelito serâ”œآ،a luego reformado para ampliarlo, y finalmente derribado. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63611100, -0.88930100, '0101000020E6100000639AE95E2775ECBF1CD0D2156CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34902197960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34902197960.webp', 'https://www.flickr.com/photos/zaragozaantigua/34902197960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21108, 'Convento de Santa Fe 1889', '"Saragosse. Une galerie du musâ”œآ®e provincial". Imagen del claustro alto del antiguo convento de la Santa Fe de la Penitencia, o Arrepentidas, fundado en el siglo XVI en plena Morerâ”œآ،a como otra de las instituciones dedicadas al recogimiento de mujeres de "vida errada y pecaminosa". En el momento de la captura fotogrâ”œأ­fica, estas instalaciones eran utilizadas como "Academia de Bellas Artes", y "Museo Provincial de Pinturas", aunque tambiâ”œآ®n de piezas de escultura, y pedazos de arquitectura. En 1908 fue demolido para ensanchar viales y hacer mâ”œأ­s grande la plaza de Salamero. Sic transit gloria mundi. Fuente: J. Lâ”œآ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65269900, -0.88390400, '0101000020E6100000F6B6990AF148ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22550936450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22550936450.webp', 'https://www.flickr.com/photos/zaragozaantigua/22550936450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21124, 'Coso alto 1889', 'Imagen centrada en el gran edificio de la Audiencia, antigua casa de los Luna, en el Coso alto. A la izquierda, el arranque de la calle de Cerdâ”œأ­n. A la derecha, la calle de la Audiencia. La captura se ha realizado, posiblemente, desde la altura de la nueva sede de la Compaâ”œâ–’â”œآ،a de Telâ”œآ®fonos Urbanos de Zaragoza.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34306656645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34306656645.webp', 'https://www.flickr.com/photos/zaragozaantigua/34306656645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21132, 'Patio de la Audiencia 1881', 'Grabado que reproduce parcialmente el patio del "Colegio de Procuradores de Zaragoza" sito en la antigua casa de los Luna, luego Morata, luego Perelada, y finalmente sede de la Audiencia Provincial, hasta el momento actual. Descansa sobre una de las columnas anilladas del lado sur del patio un paisano singular, mientras una sombra se proyecta en las escaleras del fondo, junto al ingreso principal, que a la izquierda se abre desde el Coso Alto.', 1881, 1881, 1881, 'Siglo XIX', 'CENTRO', 41.65414800, -0.88357300, '0101000020E61000008F1D54E23A46ECBF355F251FBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47669864112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47669864112.webp', 'https://www.flickr.com/photos/zaragozaantigua/47669864112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21183, 'Coso alto 1890', 'Imagen de la Audiencia Territorial, entre la calle de Cerdâ”œأ­n, a la izquierda, y la calle de la Audiencia. En el nâ”¬â•‘ 3 del Coso, a la derecha, vista parcial de la "Gran Sastrerâ”œآ،a el Non-Plus-Ultra". Fuente visual: "Palacio de Los Lunas, hoy Audiencia Territorial", en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91), a travâ”œآ®s de www.todocoleccion.net/', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34192946841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34192946841.webp', 'https://www.flickr.com/photos/zaragozaantigua/34192946841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21402, 'Coso Alto 1913', 'Inicio de la calle del Coso, con la Audiencia al fondo. Fuente: www.facebook.com/photo.php?fbid=10207584804089750&set...', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65398600, -0.88374500, '0101000020E6100000D61C2098A347ECBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23582696284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23582696284.webp', 'https://www.flickr.com/photos/zaragozaantigua/23582696284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21404, 'Coso Alto c.1915', 'Postal con vista de la Audiencia en el Coso Alto, y la calle de Cerdâ”œأ­n al fondo. Fuente: www.ebay.com/', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65394600, -0.88367000, '0101000020E61000002C9ACE4E0647ECBFCDACA580B4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25466353072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25466353072.webp', 'https://www.flickr.com/photos/zaragozaantigua/25466353072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21426, 'Calle Azoque c.1915', 'Foto: Lucas Cepero. Fachada de la tienda de ultramarinos de Federico Figueras (calle de Azoque 110), que elaboraba su propios chocolates, de marca Los Hâ”œآ®roes, en su fâ”œأ­brica de la calle de Agustina de Aragâ”œâ”‚n 42-44. A la izquierda, esquina con la calle de la Soberanâ”œآ،a Nacional, hoy Doctor Val-Carreres. Fuente visual: Colecciâ”œâ”‚n particular.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65116300, -0.88476600, '0101000020E6100000899B53C90050ECBFC0AE264F59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32949236511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32949236511.webp', 'https://www.flickr.com/photos/zaragozaantigua/32949236511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21687, 'Coso Alto c.1930', 'En primer tâ”œآ®rmino, el edificio del nâ”œâ•‘mero 5 con la Droga Alfonso, donde habâ”œآ،a vivido Luis Buâ”œâ–’uel. Al fondo a la derecha, la sirena del Banco de Aragâ”œâ”‚n, instalada en octubre de 1924. Se sustituyâ”œâ”‚ por otra en el nâ”œâ•‘mero 5 de Teniente Coronel Valenzuela, en abril de 1959. Y ahâ”œآ، sigue. Fuente visual: Archivo Mariano Arribas, en www.todocoleccion.net', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65365100, -0.88304700, '0101000020E6100000D5963AC8EB41ECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14947218675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14947218675.webp', 'https://www.flickr.com/photos/zaragozaantigua/14947218675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21691, 'Los Gigantes en el Coso 1931', '1931. Los Gigantes de la Comparsa de Gigantes y Cabezudos de Zaragoza, en posiciâ”œâ”‚n de descanso en el Coso Alto, junto a la Audiencia. La calle del fondo es Cerdâ”œأ­n. Fuente: Miguel Marâ”œآ،n Chivite, Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65396200, -0.88380500, '0101000020E61000002A52616C2148ECBFD369DD06B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15057034392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15057034392.webp', 'https://www.flickr.com/photos/zaragozaantigua/15057034392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21751, 'Iris Park 1935', 'Imagen de las seâ”œâ–’oritas postulantes de la "Fiesta de la Flor" en el complejo festivo del "Iris Park", durante la celebraciâ”œâ”‚n ofrecida en su honor el 7 de junio por la Capitanâ”œآ،a General, y con asistencia de 400 personas. La "Fiesta de la Flor" consistâ”œآ،a en una colecta de carâ”œأ­cter benâ”œآ®fico-caritativo con la que se pretendâ”œآ،a sufragar la lucha antituberculosa en Zaragoza, del mismo modo que en otras ciudades. En estas fiestas, las clases altas autocelebraban y pregonaban su generosidad para con la pobre gente afectada por esta enfermedad. En Espaâ”œâ–’a, la tuberculosis tenâ”œآ،a entonces el carâ”œأ­cter de plaga (108 muertes por cada 100.000 habitantes, en 1935). En 1924, bajo la Dictadura de Primo de Rivera, se creâ”œâ”‚ el "Patronato de la Lucha Antituberculosa" como una iniciativa privada de carâ”œأ­cter benâ”œآ®fico que se nutrâ”œآ،a de colectas, donaciones, tâ”œâ”‚mbolas, fiestas, y espectâ”œأ­culos varios. Con la Segunda Repâ”œâ•‘blica, se tratâ”œâ”‚ de estatalizar la lucha de forma planificada, con dotaciâ”œâ”‚n presupuestaria pâ”œâ•‘blica suficiente, dando prioridad a la prevenciâ”œâ”‚n, con la construcciâ”œâ”‚n de nuevos sanatorios y ambulatorios, y con personal cualificado dentro de la Sanidad Nacional. Los cambios de orientaciâ”œâ”‚n del Gobierno aceleraron o retrasaron estas polâ”œآ،ticas, y el conflicto civil iniciado en 1936 abortâ”œâ”‚ el camino y empeorâ”œâ”‚ el problema, volviendo a la senda de la beneficiencia. Hasta 1951 la tasa de muertes por tuberculosis no volviâ”œâ”‚ a los niveles de antes de la guerra. Fuente: Foto Marâ”œآ،n Chivite, "Mundo Grâ”œأ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22028391171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22028391171.webp', 'https://www.flickr.com/photos/zaragozaantigua/22028391171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21779, 'La Audiencia 1930', 'Coso Alto con el edificio del antiguo palacio de los Luna. A la izquierda, la calle de las Escuelas Pâ”œآ،as. A la derecha, calle Azoque. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65398600, -0.88374500, '0101000020E6100000D61C2098A347ECBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22952299060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22952299060.webp', 'https://www.flickr.com/photos/zaragozaantigua/22952299060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21791, 'Coso Alto aâ”œâ–’os 30', 'Foto: Miguel Marâ”œآ،n Chivite. Rebaâ”œâ–’o de pavos pastoreados en el Coso Alto, con la Audiencia a la derecha, en direcciâ”œâ”‚n a la plaza de la Constituciâ”œâ”‚n. Al fondo, tras el vehâ”œآ،culo a propulsiâ”œâ”‚n de sangre, la calle de Cerdâ”œأ­n. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65393800, -0.88371300, '0101000020E6100000FE99417C6047ECBF4ACE893DB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194247113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194247113.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194247113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21870, 'Iris Park 1932', 'Imagen con la planta del gran complejo de ocio Iris Park inaugurado en 1931 entre las calles de Azoque y Ramâ”œâ”‚n y Cajal, con la localizaciâ”œâ”‚n de sus principales espacios. Cuatro grandes edificios centralizaban su actividad: un cine -el mâ”œأ­s grande de Zaragoza en ese momento-, teatro, pista de patinaje y gran salâ”œâ”‚n de baile-restaurant. Otros espacios al aire libre completaban este lugar irrepetible, en pleno centro de la ciudad, funcional hasta comienzos de la dâ”œآ®cada de los aâ”œâ–’os cincuenta. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65146500, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF8CBE823463D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36698411415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36698411415.webp', 'https://www.flickr.com/photos/zaragozaantigua/36698411415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21875, 'Iris Park c.1934', 'Imagen capturada en el interior del festivo recinto del Iris Park, posiblemente en la zona de terrazas al aire libre entre la Pista de Baile de Verbena, el Gran Teatro de Verano y el Salâ”œâ”‚n de Cine. Tras las dos casetas que centran la imagen, traseras edilicias de los nâ”œâ•‘meros impares de la calle de la Biblioteca. Fuente visual: foto Wamba, en www.todocoleccion.net/', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65146500, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF8CBE823463D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40013399385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40013399385.webp', 'https://www.flickr.com/photos/zaragozaantigua/40013399385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21904, 'Coso Alto 1939', 'Castiza imagen capturada en el Coso alto (con vista al fondo del tramo comprendido entre los inmuebles de los nâ”œâ•‘meros 8 al 26) durante el gran desfile organizado con motivo de la visita a Zaragoza del "Caudillo" y "Generalâ”œآ،simo" para celebrar la Fiesta de la Raza el 12 de octubre de 1939 ("Aâ”œâ–’o de la Victoria"). La fotografâ”œآ،a ha sido realizada durante el desfile ante el "Palacio de la Audiencia" en cuyos balcones estaban observantes las autoridades, de la "parte tâ”œآ،pica" del desfile, integrada por representantes de la regiâ”œâ”‚n aragonesa vestidos a la manera tradicionalista y centrada en los danzantes de Tauste formando su "famosa torre" o castillo humano. Ante ellos, la tribuna montada para representantes de corporaciones, sillas ocupadas por "Caballeros mutilados", y comisiones de los cuerpos de la Guarniciâ”œâ”‚n y de las corporaciones y entidades que no cupieron en la tribuna. Sobre el adoquinado firme, vâ”œآ،as por las que transitaban los tranvâ”œآ،as de las lâ”œآ،neas 2. "Madrid", 3. "Delicias" y 7. "Ayuntamiento-Portillo".', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65383500, -0.88377700, '0101000020E6100000AE9FFEB3E647ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51683796008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51683796008.webp', 'https://www.flickr.com/photos/zaragozaantigua/51683796008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22089, 'Nuevo Teatro Iris 1955', 'Nuevo Teatro Iris de Zaragoza, dibujo de su tramoyista, Mariano Gimeno, 1955. Aspecto de la fachada del Teatro Iris de Zaragoza, poco despuâ”œآ®s de su inauguraciâ”œâ”‚n el 24 de febrero de 1955. Ese dâ”œآ،a se celebrâ”œâ”‚ un acto privado por la maâ”œâ–’ana, y por la tarde un espectâ”œأ­culo de corte baturrista titulado Raza Aragonesa. Al dâ”œآ،a siguiente, Rosario y su ballet de arte espaâ”œâ–’ol iniciaron allâ”œآ، su temporada, como se puede leer en el cartel reproducido. El edificio, de Josâ”œآ® de Yarza, con uso tambiâ”œآ®n de cine, se levantâ”œâ”‚ sobre el solar del antiguo teatro del mismo nombre que estuvo en pie entre 1931 y 1953 en el complejo de ocio Iris Park. En 1958 se le cambiâ”œâ”‚ el nombre por el de Teatro Fleta. Desde la dâ”œآ®cada de los 60 se dedicâ”œâ”‚ a la exhibiciâ”œâ”‚n de cine, hasta que cerrâ”œâ”‚ el 14 de enero de 2000, para ser posteriormente semiderruido. Fuente visual: www.elpais.com Fuente textual: Amparo Martâ”œآ،nez, Artigrama, 1999.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18964372634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18964372634.webp', 'https://www.flickr.com/photos/zaragozaantigua/18964372634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22215, 'Calle de Valenzuela 1959', 'Imagen centrada en el veterano Hotel Lafuente sito en la calle del Teniente Coronel Valenzuela, tras una reforma que le habâ”œآ،a conferido este luminoso aspecto moderno. A su izquierda, la nueva e imponente sede central del Banco de Aragâ”œâ”‚n. A su derecha, el inmueble del nâ”¬â•‘ 9. La escena estâ”œأ­ capturada desde el encuentro de la referida calle, antigua de la Morerâ”œآ،a, con la plaza de Salamero, antigua de la Santa Fe, con una leve vista de la esquina del colegio de las madres Escolapias, en primer tâ”œآ®rmino y a la izquierda. Fuente visual: AMZ', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65269900, -0.88310000, '0101000020E61000008A1F63EE5A42ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46182132844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46182132844.webp', 'https://www.flickr.com/photos/zaragozaantigua/46182132844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22278, 'Lola Flores 1962', '"Lola Flores asiste al estreno de "El balcâ”œâ”‚n de la Luna" en el Gran Teatro Fleta de Zaragoza el 4 de febrero de 1962 - Foto: Parâ”œآ،s (Zaragoza) - Gentileza de â”œأ¼ngel Villaverde Rubio (Zaragoza)" rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65148800, -0.88513700, '0101000020E61000007D586FD40A53ECBF44DE72F563D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981505086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981505086.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981505086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22477, 'Pl. de Salamero 1968', 'Imagen realizada por Joaquâ”œآ،n Alcâ”œâ”‚n Pueyo y centrada en el acceso al bar El Pozal, sito en la fachada meridional de la plaza de Salamero (antigua de Santa Fe), tramo entre la calle del Requetâ”œآ® Aragonâ”œآ®s (hacia la izquierda) y la del Azoque (hacia la derecha). Este establecimiento de bebidas espirituosas formaba parte del paisaje emocional de la plaza desde su apertura en 1922, y se consolidâ”œâ”‚ como puntual lugar de encuentro de destacadas personalidades de la intelectualidad de la â”œآ®poca, como artistas, escritores, toreros, et caetera. Pâ”œâ•‘blico en general y trabajadores constituâ”œآ،an el grueso de su parroquia hasta que cerrâ”œâ”‚ en los aâ”œâ–’os 80. Tras el derribo del antiguo edificio (nâ”œâ•‘meros 3-4 de la plaza) sobre su solar fue construido el actual bloque del nâ”¬â•‘ 1 de la calle Azoque. Llamativamente, en el momento de realizar esta captura la publicidad exterior mâ”œأ­s visible resultaba ser la de una bebida carbonatada inalcohâ”œâ”‚lica de origen norteâ”œâ–’o. Fuente visual: web.dpz.es/arscatalogi.es/', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65197800, -0.88397900, '0101000020E61000009F39EB538E49ECBF12DBDD0374D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34883020313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34883020313.webp', 'https://www.flickr.com/photos/zaragozaantigua/34883020313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22579, 'Audiencia 1977', 'Toma del tramo del Coso Alto a la altura del palacio de la Audiencia de Zaragoza, en 1977. Al fondo, manzana entre las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as, en demoliciâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=865591303474446&set=o...', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65383500, -0.88356200, '0101000020E610000094A0BFD02346ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15561899027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15561899027.webp', 'https://www.flickr.com/photos/zaragozaantigua/15561899027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22622, 'Calle Azoque 1977', 'Imagen de la antigua calle de Azoque mirando hacia lo que fue la plazuela de Luis Santâ”œأ­ngel, y el inmediato emboque hacia el Coso Alto. Tras los derribos y ensanches realizados a izquierda (calle Pignatelli, callejâ”œâ”‚n de Serâ”œâ”‚n desaparecido), y derecha (calle Palomeque), la calle Azoque parece haberse convertido en una triste calleja: es lo que sucede cuando se altera la escala y proporciones urbanas. Hasta este momento, y durante siglos, no parecâ”œآ،a problemâ”œأ­tico que este fuera el modelo urbanâ”œآ،stico de la zona. El problema comenzâ”œâ”‚ cuando hubo que comenzar a inventarse espacios donde no los habâ”œآ،a para que el vehâ”œآ،culo privado a motor de explosiâ”œâ”‚n, un reciâ”œآ®n llegado, pudiera moverse como si la milenaria ciudad le hubiera tocado en una rifa, y fuera suya. Al poco tiempo, la Avenida de Câ”œآ®sar Augusto se abrirâ”œأ­ paso por aquâ”œآ، a golpe de nuevos derribos, para consolidar una urbana autovâ”œآ،a desde el puente de Santiago, y hasta la puerta del Carmen, abriendo una trinchera de asfalto y trâ”œأ­fico rodado por la vieja Morerâ”œآ،a, jalonada ademâ”œأ­s por nuevos, modernos y enormes edificios residenciales. Al fondo, y a la derecha, aâ”œâ•‘n puede verse el remate de una de las torres del antiguo palacio de los Luna-Morata.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65361900, -0.88408800, '0101000020E61000004E27D9EA724AECBFA98592C9A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19785652132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19785652132.webp', 'https://www.flickr.com/photos/zaragozaantigua/19785652132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22664, 'Iglesia de Santiago 1971', 'Iglesia de Santiago el Mayor en una vista de su fachada principal capturada desde la plaza de Miguel Salamero. En primer tâ”œآ®rmino, restos de la manzana comprendida entre la calle del Azoque y la de San Ildefonso, al fondo, derribada para dar continuidad a la avenida Imperial y ampliar la calle del Doctor Gâ”œâ”‚mez Ulla (luego desaparecida). Aâ”œâ–’os despuâ”œآ®s, sobre estos solares se construirâ”œآ،a tambiâ”œآ®n un impactante bloque de oficinas comerciales.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65239100, -0.88438900, '0101000020E61000000B26FE28EA4CECBF359A5C8C81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22756748059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22756748059.webp', 'https://www.flickr.com/photos/zaragozaantigua/22756748059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22971, 'Teatro Fleta aâ”œâ–’os 90', 'Foto Gonzalo Bullâ”œâ”‚n. El teatro Fleta fue un edificio de Josâ”œآ® de Yarza construido en 1955 y usado casi exclusivamente como cine en sus â”œâ•‘ltimos aâ”œâ–’os. En el cambio de siglo posterior se derribâ”œâ”‚, dejando la fachada en pie.', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009818245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009818245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009818245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23207, 'Calle Morata 2010', 'Foto: Oliver Duch. Solar entre las calles de Morata (tras el fotâ”œâ”‚grafo) y Galo Ponte (a la izquierda). Albergarâ”œأ­ desde 2012 la sede de la Audiencia Provincial de Zaragoza, dejando al palacio de los Luna (derecha) como Tribunal Superior de Justicia de Aragâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65446500, -0.88302800, '0101000020E61000002579AEEFC341ECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32824462223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32824462223.webp', 'https://www.flickr.com/photos/zaragozaantigua/32824462223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23497, 'Coso Alto 1877', 'Bajo una intensa solanera de la segunda quincena del mes de junio y desde el resguardo de la altura relativa de la Casa de las Monas, una visual del Coso Alto que quita el aliento, desde la Audiencia, inmediata, hasta la plaza de la Constituciâ”œâ”‚n, al fondo, pasando por algunas de las aâ”œâ–’ejas casas de la alta nobleza indâ”œآ،gena.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65386700, -0.88359400, '0101000020E61000006C239EEC6646ECBF8177F2E9B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679887379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679887379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679887379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23501, 'Portada de la Audiencia 1889', 'J. Lâ”œآ®vy et Cie, 1889 Puerta de de entrada del palacio de los Condes de Morata o de los Luna, sede de la Audiencia. Las figuras que la custodian a ambos lados son consideradas representaciones de Teseo y Hâ”œآ®rcules. El humorista Chas bautizâ”œâ”‚ a los gigantes como "Que te zumbo" y "Que te arreo":', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65396700, -0.88366000, '0101000020E610000049111956F146ECBFE5D4CE30B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14988388541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14988388541.webp', 'https://www.flickr.com/photos/zaragozaantigua/14988388541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23503, 'Palacio de Torresecas c.1859', 'Patio de la Casa de los Condes de Torres Secas en Zaragoza. Valentâ”œآ،n Carderera. 1832-1880. El palacio de Torresecas estaba enclavado en la calle Coso, en el actual nâ”¬â•‘ 5 (edificio de Drogas Alfonso), junto a un portillo abierto en 1271 en la muralla romana para acceder al Coso desde la plaza de San Felipe, que dio lugar a la calleja luego denominada Torresecas, cerrada posteriormente. En la imagen, dibujo del renacentista patio central del palacio de Torresecas. Fuente: "Viaje artâ”œآ،stico por Aragâ”œâ”‚n de Valentâ”œآ،n Carderera", Josâ”œآ® Marâ”œآ،a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano, 2013.', 1859, 1859, 1859, 'Siglo XIX', 'CENTRO', 41.65365100, -0.88304700, '0101000020E6100000D5963AC8EB41ECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15572225330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15572225330.webp', 'https://www.flickr.com/photos/zaragozaantigua/15572225330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23504, 'Cabezudos y Gigantones 1872', 'Dibujo: Pradilla; grabado: Capuz. 1872. "Zaragoza. Fiestas del Pilar: los Cabezudos y Gigantones." Grabado de los gigantes, en su denominaciâ”œâ”‚n decimonâ”œâ”‚nica, y cabezudos, animando la calle en las fiestas mayores, delante del Palacio de Los Luna, al comienzo del Coso Alto. Hâ”œآ®rcules y Teseo, entoldados, casi sâ”œâ”‚lo se les ven las garrotas. A la izquierda, la calle de la Albarderâ”œآ،a que conduce a la plaza del Mercado. A la derecha, fuera de imagen, la Casa-Palacio de los Condes de Torresecas. Fuente: "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana", Madrid, Aâ”œâ–’o XVI, nâ”¬â•‘ XXXIX, 16-10-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CENTRO', 41.65396200, -0.88380500, '0101000020E61000002A52616C2148ECBFD369DD06B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717871910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717871910.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717871910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23506, 'Cristo de la Cama 1885', 'Procesiâ”œâ”‚n de Viernes Santo. "Paso" titulado "La Cama de Nuestro Seâ”œâ–’or". Dibujo de Marcelino de Unceta. Paseando a Cristo muerto por el Coso Alto, antes de que resucite. Al fondo, manzana entre las calles de Cerdâ”œأ­n y de las Escuelas Pâ”œآ،as. A su derecha, la Audiencia. Fuente: Biblioteca Nacional de Espaâ”œâ–’a.', 1885, 1885, 1885, 'Siglo XIX', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15904257796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15904257796.webp', 'https://www.flickr.com/photos/zaragozaantigua/15904257796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23507, 'Palacio de los Luna c.1891', '"Porte de l''Intendance â”œأ، Saragosse", Hubert Vaffier, 1891. El renacentista y magnâ”œآ،fico Palacio de los condes de Morata, de mediados del XVI, pasâ”œâ”‚ despuâ”œآ®s a manos del conde de Peralada, que antes de devolver el alma a su creador, testâ”œâ”‚ en 1728 esta propiedad en beneficio del primer borbâ”œâ”‚n rey de Espaâ”œâ–’a, Felipe. Luego fue convertido en sede de la Capitanâ”œآ،a General (1760-1814), para convertirse despuâ”œآ®s en sede de la Intendencia, primero, y de la Audiencia Territorial de Zaragoza, despuâ”œآ®s. En la imagen, chavales trasteando en la puerta del Coso Alto de la Audiencia, con Teseo y Hâ”œآ®rcules (los "Gigantes", eran denominados) como si fueran de piedra.', 1891, 1891, 1891, 'Siglo XIX', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16067750383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16067750383.webp', 'https://www.flickr.com/photos/zaragozaantigua/16067750383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23510, 'Palacio de la Audiencia c.1840', 'Vista de la fachada principal del palacio de la Audiencia de Zaragoza, dibujo a lâ”œأ­piz de Valentâ”œآ،n Carderera, ca. 1840. Fuente: ceres.mcu.es/', 1840, 1840, 1840, 'Siglo XIX', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21112031952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21112031952.webp', 'https://www.flickr.com/photos/zaragozaantigua/21112031952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23514, 'Colegio Escolapias 1930', 'Patio del colegio de MM. Escolapias. Imagen del antiguo patio del colegio de Santo Tomâ”œأ­s de Villanueva y San Jorge, de los PP. Agustinos Observantes, sito en la plazuela de la Manterâ”œآ،a. Asociado a la fâ”œأ­brica de la iglesia y demâ”œأ­s dependencias colegiales de esta Orden, fue realizado a finales del siglo XVII en limpias formas barrocas, y ladrillo como material fundamental. En 1883 fue adquirido por las MM. Escolapias, que realizaron en â”œآ®l varias intervenciones, de resultas de las cuales este viejo patio se quedâ”œâ”‚ por el camino de la nada. Fuente visual: Foto R. Saus, en www.todocoleccion.net/', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65301200, -0.88323900, '0101000020E6100000E3A7716F7E43ECBFA1F2AFE595D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25008074384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25008074384.webp', 'https://www.flickr.com/photos/zaragozaantigua/25008074384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23519, 'Calle Galo Ponte 2006', 'Foto: Josâ”œآ® Miguel Marco. Vista de la calle de Galo Ponte, con el palacio de los Luna en el Coso Alto a la izquierda, y a la derecha el solar que albergarâ”œأ­ desde 2012 el nuevo edificio de la Audiencia Provincial de Zaragoza, dejando al palacio como sede del Tribunal Superior de Justicia de Aragâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65399200, -0.88324200, '0101000020E610000027840EBA8443ECBF3EEC8502B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31332067263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31332067263.webp', 'https://www.flickr.com/photos/zaragozaantigua/31332067263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23521, 'Coso Alto 1874', 'Dibujo a tinta y aguada que representa el patio interior de la casa situada frente a la puerta del palacio de los condes de Morata, en el Coso Alto. Posiblemente se trate de la antigua casa del siglo XV-XVI que a principios del siglo XVIII fuera del tesorero de la Real Audiencia, Vicente Jimâ”œآ®nez de Baguâ”œآ®s. Desaparecida.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65385100, -0.88382000, '0101000020E6100000809F71E14048ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32124507516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32124507516.webp', 'https://www.flickr.com/photos/zaragozaantigua/32124507516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23522, 'Vista desde La Adriâ”œأ­tica 2011', 'Foto: Oliver Duch. Vista desde el edificio La Adriâ”œأ­tica, en el Coso Alto 34, de la evoluciâ”œâ”‚n de las obras de la nueva Audiencia de Zaragoza, a finales de septiembre de 2011. Tras las redes, se puede ver la câ”œâ•‘pula geodâ”œآ®sica del museo Pablo Gargallo, y mâ”œأ­s allâ”œأ­ del puente de Santiago, tambiâ”œآ®n en obras para el paso del tranvâ”œآ،a, la margen izquierda hasta el Parque Goya. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65426500, -0.88312200, '0101000020E61000007E198C118942ECBF6FF59CF4BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37771244134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37771244134.webp', 'https://www.flickr.com/photos/zaragozaantigua/37771244134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23526, 'Plaza de San Roque c.1935', 'Imagen centrada en la barroca fâ”œأ­brica en ladrillo de la iglesia de la Manterâ”œآ،a, que formara parte del antiguo colegio de Santo Tomâ”œأ­s de Villanueva, y que desde 1883 formaba parte del anexo colegio de las madres escolapias. A la derecha, la calle de Agustâ”œآ،n Palomeque. En su fuente original, esta imagen aparece identificada como "fachada edificio barroco" y localizada en La Almunia de Doâ”œâ–’a Godina. En GAZA nos hemos permitido reubicarla en su histâ”œâ”‚rico emplazamiento zaragozano.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65319400, -0.88314400, '0101000020E61000007313B534B742ECBFC2F869DC9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50111563083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50111563083.webp', 'https://www.flickr.com/photos/zaragozaantigua/50111563083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23527, 'Audiencia Provincial 1895', 'Imagen capturada en el patio de la gran casa de mediados del siglo XVI de los Luna o Morata, que en 1725 fue donada por el conde de Perelada al rey Felipe V y habilitada poco despuâ”œآ®s como residencia del capitâ”œأ­n general de Aragâ”œâ”‚n. Entre 1809 y 1813 fue la residencia del mariscal Jean Lannes, responsable de la administraciâ”œâ”‚n francesa ocupante. En 1814, recuperada la normalidad del Antiguo Râ”œآ®gimen, fue promovida a sede de la Audiencia Provincial, funciâ”œâ”‚n que perdura en la actualidad. Centra la escena el monumento labrado por el escultor Carlos Palao en 1885 y dedicado a la Justicia. El aspecto del patio fue radicalmente transformado en la reforma proyectada por el arquitecto Regino Borobio Ojeda y desarrollada entre 1921 y 1929. En la actualidad, este bulto redondo se encuentra orillado junto a la escalera noble de la izquierda, si bien en un pedestal mâ”œأ­s pequeâ”œâ–’o y desprovisto de ornamentaciâ”œâ”‚n.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65413200, -0.88344400, '0101000020E6100000191EFB592C45ECBF2FA2ED98BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50123168928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50123168928.webp', 'https://www.flickr.com/photos/zaragozaantigua/50123168928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23528, 'Coso Alto c.1931', 'Imagen capturada desde la altura de la antigua Casa de las Monas y centrada en el arranque del tramo alto del Coso. A la izquierda inaugura la calle el edificio que alberga a la Audiencia Territorial, hasta la homâ”œâ”‚nima calle tras la que comienzan los inmuebles desde el nâ”¬â•‘ 3. A la derecha, tramo del lado de los pares, desde el inmediato y chaflanero nâ”¬â•‘ 8 que albergaba la consulta del dentista Luis Mundi, y el espacioso local comercial de Eusebio Omist, que por la parte trasera llegaba hasta el nâ”¬â•‘ 5 de la calle de Agustâ”œآ،n Palomeque, y en el que destacaba la tienda de ropa blanca "El Bebâ”œآ®". En primer tâ”œآ®rmino, curvea hacia la calle de Juan Jimâ”œآ®nez Cerdâ”œأ­n el tendido tranviario de la reciente lâ”œآ،nea 7. Ayuntamiento-Portillo.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65395100, -0.88377700, '0101000020E6100000AE9FFEB3E647ECBFDF1797AAB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50704847663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50704847663.webp', 'https://www.flickr.com/photos/zaragozaantigua/50704847663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23529, 'Plaza de San Roque 1874', 'Imagen capturada en la plaza o plazuela de San Roque y centrada en la fachada de la antigua iglesia del colegio de Santo Tomâ”œأ­s de Villanueva, llamada de la Manterâ”œآ،a por albergar tambiâ”œآ®n a la cofradâ”œآ،a de los manteros. Tras la exclaustraciâ”œâ”‚n del inmueble en 1835, â”œآ®ste pasâ”œâ”‚ por dispares usos como almacâ”œآ®n de grano y fâ”œأ­brica de harina para el ramo de la Guerra durante la primera guerra civil carlista, ademâ”œأ­s de cuartel; a mediados de siglo la iglesia fue parroquia castrense, y el colegio acogiâ”œâ”‚ un correccional de mujeres. En el tiempo en que fue realizada esta fotografâ”œآ،a, era parque de artillerâ”œآ،a de la milicia y almacâ”œآ®n de provisiones. En la imagen y a la derecha, vista parcial del lado de los impares de la inmediata calle de Agustâ”œآ،n de Lezo Palomeque, antigua de la Manterâ”œآ،a.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65320200, -0.88320800, '0101000020E61000002219726C3D43ECBF45D7851F9CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51413822047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51413822047.webp', 'https://www.flickr.com/photos/zaragozaantigua/51413822047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23530, 'Coso Alto 1890', 'Coloreada imagen capturada desde la altura de la central de los telâ”œآ®fonos urbanos y centrada en el principio del tramo alto del Coso, donde destaca la gran fachada de la Audiencia Territorial con su quiosco de prensa en la puerta. A la izquierda la calle de Juan Jimâ”œآ®nez Cerdâ”œأ­n, y a la derecha la calle de la Audiencia y el arranque del inmueble del nâ”¬â•‘ 3 del Coso, en cuyos bajos se abrâ”œآ،a la "Gran Sastrerâ”œآ،a El Non Plus Ultra", especializada en ropa eclesiâ”œأ­stica. Sobre el firme, vâ”œآ،as de la lâ”œآ،nea Circunvalaciâ”œâ”‚n por donde circulaban coches arrastrados por caballerâ”œآ،as.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65399600, -0.88375500, '0101000020E6100000B9A5D590B847ECBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51423854245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51423854245.webp', 'https://www.flickr.com/photos/zaragozaantigua/51423854245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23533, 'Coso alto 1878', 'Imagen capturada por el fotâ”œâ”‚grafo villanovense Gregorio Sabatâ”œآ® Fâ”œآ®rriz e integrada en el â”œأ­lbum "Vistas de Zaragoza", centrada en la imponente fachada del original palacio de los Luna del siglo XVI, luego de los condes de Morata y finalmente de los condes de Peralada, que en 1725 donaron al rey Felipe V para que fuera su residencia Real durante sus estancias en la ciudad. Mientras tanto, ejercâ”œآ،a de residencia del Capitâ”œأ­n General y presidente de la Real Audiencia. En 1834 fueron creadas las Audiencias Territoriales como tribunal superior de Justicia de Distrito para causas civiles y criminales, y este edificio se convirtiâ”œâ”‚ en su sede. En 1882 esta instituciâ”œâ”‚n fue reconvertida en Audiencia Territorial, con menos funciones. En la imagen, el inmueble sito en el arranque a la izquierda del tramo alto del Coso desde la antigua Casa de las Monas localizada entre las calles de Juan Jimâ”œآ®nez Cerdâ”œأ­n y de las Escuelas Pâ”œآ،as. La fachada se muestra con su hechura original, antes de la intervenciâ”œâ”‚n que en los aâ”œâ–’os 20 del siglo XX le confiriâ”œâ”‚ su actual aspecto. Destaca su mâ”œأ­s que interesante portada de ingreso, flanqueada por las grandes figuras de los hâ”œآ®roes mitolâ”œâ”‚gicos Hâ”œآ®rcules y Teseo. Su tamaâ”œâ–’o hizo que popularmente fueran denominados como "gigantes", y su actitud llevâ”œâ”‚ incluso a bautizarlos castizamente como "que te zurro" y "que te arreo", lo que referido a una instalaciâ”œâ”‚n donde se imparte Justicia, resulta cuando menos inquietante, sobre todo si no tienes los contactos sociales adecuados.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65402800, -0.88372300, '0101000020E6100000E222F7747547ECBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54762763419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54762763419.webp', 'https://www.flickr.com/photos/zaragozaantigua/54762763419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23992, 'Teatro Iris 1942', 'Grupo de siete elefantes en el escenario del Teatro Iris, durante una representaciâ”œâ”‚n circense. Fuente: Artigrama, 1995', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19359846658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19359846658.webp', 'https://www.flickr.com/photos/zaragozaantigua/19359846658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24061, 'Teatro Fleta 2005', 'Entre 2001 y 2005 se realizaron excavaciones arqueolâ”œâ”‚gicas en el subsuelo del antiguo Teatro Fleta. Se hallaron restos de los siglos XI al XV. En la foto, prospecciones en el patio de butacas, bajo una carpa provisional. Fuente visual: www.cdl-aragon.es/', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65181200, -0.88507700, '0101000020E610000029232E008D52ECBFF7915B936ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32302739431.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32302739431.webp', 'https://www.flickr.com/photos/zaragozaantigua/32302739431/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24067, 'Coso Alto 1975', 'Otoâ”œâ–’al imagen de la comparsa de los diez gigantes en el arranque del Coso Alto: Rey, Reina, Duque, Duquesa, Chino, Negra, Don Quijote, Dulcinea, Bearnâ”œآ®s, y Bearnesa. La cabezuda Forana saluda a algunos pardales. Al fondo, a la izquierda, el colegio de los Escolapios, y la manzana entre Escuelas Pâ”œآ،as, y Cerdâ”œأ­n. En el centro, la Audiencia, y la calle Galo Ponte. A su derecha, el antiguo nâ”¬â•‘ 3 del Coso, luego derribado, y despuâ”œآ®s, el nâ”¬â•‘ 5, con Drogas Alfonso en sus bajos. A la derecha, el nâ”¬â•‘ 7, y un pedazo del saliente que anuncia el ingreso al Cine Coso. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33577360015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33577360015.webp', 'https://www.flickr.com/photos/zaragozaantigua/33577360015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24973, 'Coso Alto 1942', 'Foto de 21 de mayo de 1942, tomada en el Coso Alto de Zaragoza, a la altura de la Audiencia. Una joven pasea en bicicleta. Al fondo, los Escolapios. Fuente: www.facebook.com/photo.php?fbid=712500898834172&set=g...', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19440935908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19440935908.webp', 'https://www.flickr.com/photos/zaragozaantigua/19440935908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25154, 'Palacio de Morata aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste que muestra la portada del palacio de los condes de Morata o de los Luna, luego Audiencia, en el Coso Alto. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65392800, -0.88369300, '0101000020E61000003788D68A3647ECBF27F8A6E9B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627339493.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627339493.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627339493/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25687, 'Plaza de Salamero 1974', 'Derribo del inmueble del nâ”¬â•‘ 2 de la calle del Requetâ”œآ® Aragonâ”œآ®s, construido a principios del siglo cuando era la calle del Cinco de Marzo, posiblemente diseâ”œâ–’ado por Fernando de Yarza, en una vista desde la plaza de Miguel Salamero. Su solar lo ocuparâ”œآ،a luego un moderno edificio. A la derecha, Bar el Pozal, y una puertecita con celosâ”œآ،as en ladrillo de acceso al colegio de Santa Rosa. A la izquierda, puesto de castaâ”œâ–’era con saco de carbâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65197600, -0.88374400, '0101000020E6100000BF28417FA147ECBF71E316F373D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14851661532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14851661532.webp', 'https://www.flickr.com/photos/zaragozaantigua/14851661532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25688, 'Santiago el Mayor 1940', 'AHPZ-Archivo Coyne, Manuel Coyne, 1940. Fachada y torres de la Iglesia de San Ildefonso (o de Santiago el Mayor).', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65224800, -0.88507500, '0101000020E6100000FB3A70CE8852ECBFD270CADC7CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857858436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857858436.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857858436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25689, 'Calle de San Ildefonso 1930', '"Iglesia de Santiago".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65237600, -0.88513400, '0101000020E6100000397CD2890453ECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875365745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875365745.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875365745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25690, 'Plaza de Salamero 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Octubre 1974. Imagen de la entrada a la remodelada Plaza de Salamero desde la flamante y nueva Avenida de Câ”œآ®sar Augusto, con la iglesia de Santiago el Mayor al fondo. Los solares, a izquierda y derecha de la Plaza, estâ”œأ­n pendientes de ser construidos con modernos bloques de viviendas y de oficinas.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65252900, -0.88492500, '0101000020E6100000A835CD3B4E51ECBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14882405296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14882405296.webp', 'https://www.flickr.com/photos/zaragozaantigua/14882405296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25691, 'Torre derecha Santiago 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Noviembre 1972. La iglesia de Santiago el Mayor es el â”œâ•‘nico vestigio del antiguo Convento de San Ildefonso de la Orden de Santo Domingo. Es la iglesia barroca de mayores proporciones en Zaragoza. El convento fue fundado por don Alonso de Villalpando, iniciâ”œأ­ndose su construcciâ”œâ”‚n en 1651. Los trabajos se desarrollan a lo largo de la segunda mitad del siglo XVII. El convento fue abandonado tras la Desamortizaciâ”œâ”‚n de Mendizâ”œأ­bal en 1836. En 1860 la câ”œâ•‘pula original quedâ”œâ”‚ destruida tras recibir el impacto de un rayo. Se rehizo siguiendo la estâ”œآ®tica barroca y en 1964-1965 se restaurâ”œâ”‚ y cubriâ”œâ”‚ con tejas vidriadas de Manises, creando un efecto similar al de las câ”œâ•‘pulas de la Basâ”œآ،lica del Pilar. En 1902 el edificio pasa a ser la sede de la parroquia de Santiago, cuya iglesia habâ”œآ،a sido derribada. En la dâ”œآ®cada de 1970, el arquitecto Fernando Chueca Goitia recreciâ”œâ”‚ las torres de la fachada aâ”œâ–’adiendo los cuerpos de remate, dentro de una estâ”œآ®tica entre lo barroco-clasicista, y lo neoclasicista. En la imagen, andamiajes de la obra de recrecimiento en la torre derecha. Las obras de derribo para la apertura de la Avenida de Câ”œآ®sar Augusto, continâ”œâ•‘an.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65247300, -0.88480100, '0101000020E6100000A4FACE2F4A50ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14902109661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14902109661.webp', 'https://www.flickr.com/photos/zaragozaantigua/14902109661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25693, 'Avenida Câ”œآ®sar Augusto 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Octubre 1974. Imagen de la flamante y nueva Avenida de Câ”œآ®sar Augusto, en el tramo de la iglesia de Santiago el Mayor, a su derecha, y la remodelada Plaza de Salamero, a su izquierda.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65272900, -0.88473200, '0101000020E61000008330B77BB94FECBF4D13B69F8CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14905366675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14905366675.webp', 'https://www.flickr.com/photos/zaragozaantigua/14905366675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25694, 'Câ”œآ®sar Augusto 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/09/1974. Imagen desde la nueva Avenida de Câ”œآ®sar Augusto de las obras de urbanizaciâ”œâ”‚n del entorno del antiguo Hospital Militar. A la derecha, la iglesia de Santiago el Mayor. La calle que se abre es la de Camâ”œâ”‚n Aznar, y la calle del fondo, con las ventanas del bloque de viviendas aâ”œâ•‘n con las marcas en los cristales, Ramâ”œâ”‚n y Cajal. A la izquierda, solares donde pronto se levantarâ”œأ­n nuevos bloques habitacionales de 7 y 8 alturas, junto al Hotel Corona de Aragâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65223200, -0.88522000, '0101000020E6100000DD7BB8E4B853ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945608811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945608811.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945608811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25695, 'Hospital militar 1930', 'Archivo Vâ”œآ،ctor Barâ”œâ”‚n. 1930 "Imagen del desaparecido hospital militar de la calle de San Ildefonso, al lado de la iglesia de Santiago. Funcionâ”œâ”‚ como tal desde 1816 hasta 1958, en que se inaugurâ”œâ”‚ el del paseo de Isabel La Catâ”œâ”‚lica."', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65269700, -0.88487700, '0101000020E61000006571FF91E950ECBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957750336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957750336.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957750336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25696, 'Plaza de Salamero 1972', '1972. Imagen de la Plaza de Salamero, remodelada y convertida en Postal tras la reciente construcciâ”œâ”‚n del aparcamiento subterrâ”œأ­neo. La vista se orienta hacia la manzana que da al Coso. A la derecha, la calle Teniente Coronel Valenzuela. A la izquierda, espacios en vâ”œآ،as de extinciâ”œâ”‚n: el tramo de la calle Azoque que conectaba el Coso con la Plaza, la Plaza de Luis Santâ”œأ­ngel, y la calle Serâ”œâ”‚n. Lo mismo le sucede a la manzana a la izquierda de la Plaza, menguada para ensanchar la Avenida de Câ”œآ®sar Augusto. Aunque, en este caso, las nuevas alturas superarâ”œأ­n todo lo visto anteriormente. Todo.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65212000, -0.88412000, '0101000020E610000026AAB706B64AECBFA4880CAB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14977412465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14977412465.webp', 'https://www.flickr.com/photos/zaragozaantigua/14977412465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25697, 'Hospital de San Ildefonso 1925', 'Durante los enfrentamientos bâ”œآ®licos del Reino de Espaâ”œâ–’a con el I Imperio Francâ”œآ®s a comienzos del XIX, y ante el colapso de las instalaciones sanitarias de la ciudad, el convento de San Ildefonso fue habilitado como "Hospital de Sangre de San Ildefonso" para cuidado y atenciâ”œâ”‚n a heridos por causa de la guerra. Este hospital provisional o de campaâ”œâ–’a, al igual que ocurriâ”œâ”‚ con el de Convalecientes, con el paso de los aâ”œâ–’os terminarâ”œآ،a siendo un hospital militar fijo denominado "Hospital Militar de San Ildefonso", instalaciâ”œâ”‚n que permaneciâ”œâ”‚ en funcionamiento 150 aâ”œâ–’os. Se trata de la fachada principal del antiguo Hospital Militar de San Ildefonso, establecido desde el principio del siglo XIX en el antiguo y homâ”œâ”‚nimo convento, con la iglesia de Santiago (antigua del convento), a la derecha. El espacio de primer tâ”œآ®rmino era la plaza de San Ildefonso a espaldas de la calle de la Biblioteca, con la calle de San Ildefonso a la derecha. Entre tanto solemne ladrillo barroco, unos pardales hacen una pausa en sus juegos y posan en la rinconera del centro de la imagen. La parte trasera del hospital daba a la calle de Ramâ”œâ”‚n y Cajal. Este hospital estuvo aquâ”œآ، operativo hasta su derribo y traslado a la Vâ”œآ،a Ibâ”œآ®rica en los aâ”œâ–’os 60 del pasado siglo XX.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65228800, -0.88531100, '0101000020E6100000F23FF9BB7754ECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981591729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981591729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981591729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21935, 'La montaâ”œâ–’a de Bruil 1941', '"Parque de Torre de Bruil antes de la reforma." En la calle Asalto 38 (tramo entre Palomar y Alonso V) tenâ”œآ،a su entrada la Torre de Bruil, cuyo edificio-vivienda con fachada a la calle no hacâ”œآ،a justicia al amplâ”œآ،simo y exuberante recinto al aire libre orientado hacia el Huerva, con un parque y jardines muy destacables y afamados. Fue ordenada su construcciâ”œâ”‚n por el dueâ”œâ–’o del terreno, Juan Faustino Bruil, siendo terminada la obra en 1844. Constaba la Torre de una "montaâ”œâ–’a rusa" de 25 metros de altura construida a modo de atalaya desde la que dominar visualmente el entorno. Se ascendâ”œآ،a mediante una escalera de madera adosada. A la montaâ”œâ–’a tambiâ”œآ®n se habâ”œآ،an horadado varias cavidades a modo de cuevas. Fuente: Archivo Municipal de Zaragoza. Aportada por Gerardo Sancho Ramo. 1941.', 1941, 1941, 1941, 'Anos 40', 'LAS FUENTES', 41.64992300, -0.86800500, '0101000020E61000009F76F86BB2C6EBBF88F546AD30D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15178171317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15178171317.webp', 'https://www.flickr.com/photos/zaragozaantigua/15178171317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25702, 'Calle Azoque c.1972', 'Tramo de la calle del Azoque entre el principio de la calle de Pignatelli y el callejâ”œâ”‚n del Serâ”œâ”‚n, a la izquierda y fuera de plano. A la derecha, restos de la plazuela de Luis Santâ”œأ­ngel encajonada entre las calles de Agustâ”œآ،n Palomeque, y de la Morerâ”œآ،a, desde donde en primer plano aparece un ciclista . Tras derribos y ensanches, el tramo de la calle del Azoque que al fondo arranca desde el Coso asemeja una lâ”œâ•‘gubre calleja: es lo que sucede cuando se alteran la escala y proporciones urbanas. Durante siglos, y hasta la irrupciâ”œâ”‚n del trâ”œأ­fico rodado de masas, este fue el tradicional modelo urbanâ”œآ،stico de este y otros espacios de la ciudad. Poco despuâ”œآ®s, para dar continuidad a la avenida Imperial como urbana autovâ”œآ،a entre el puente de Santiago y la puerta del Carmen, la trinchera de asfalto y trâ”œأ­fico rodado transformarâ”œآ،a radicalmente esta zona de la vieja Morerâ”œآ،a.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65361900, -0.88408800, '0101000020E61000004E27D9EA724AECBFA98592C9A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22551445163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22551445163.webp', 'https://www.flickr.com/photos/zaragozaantigua/22551445163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25706, 'Calle de Valenzuela c.1977', 'Calle del Teniente Coronel Valenzuela desde la plaza de Miguel Salamero. A la derecha, inmediato y en servicio desde los aâ”œâ–’os 20, el Hotel Lafuente. A continuaciâ”œâ”‚n, la rotunda presencia del Banco de Aragâ”œâ”‚n, de la que se destaca la sonora bocina que originalmente estuviera sobre la antigua sede de este banco, frente a la calle de Alfonso I. A la izquierda, esquina del colegio de las madres Escolapias. Al fondo, el edificio del Cine Coso.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65266400, -0.88324100, '0101000020E610000011902FA18243ECBF66A3737E8AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23984078893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23984078893.webp', 'https://www.flickr.com/photos/zaragozaantigua/23984078893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25707, 'Plaza Salamero 1972', 'La plaza de Miguel Salamero, antigua de Santa Fe, en una colorista imagen capturada en altura desde el lado sur durante la â”œâ•‘ltima fase de urbanizaciâ”œâ”‚n de este espacio, tras las obras de construcciâ”œâ”‚n del aparcamiento subterrâ”œأ­neo con capacidad para 340 vehâ”œآ،culos. A la izquierda, tramo de la calle del Azoque delimitado entre las calles de Telesforo Peromarta, al fondo, y del Doctor Mariano Gâ”œâ”‚mez Ulla, fuera de plano, con vista parcial de la manzana de viviendas derribadas poco despuâ”œآ®s. En el centro de la escena, la manzana comprendida entre la calle del Azoque y la del Teniente coronel Valenzuela, fuera de plano, con una escalonada vista del colegio de las madres Escolapias y la barroca câ”œâ•‘pula de la anexa iglesia de la Manterâ”œآ،a; del edificio de Seguros La Adriâ”œأ­tica, detrâ”œأ­s; y de la vertical estructura del inmueble en construcciâ”œâ”‚n del nâ”¬â•‘ 24 del Coso Alto.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65243100, -0.88393900, '0101000020E6100000121615713A49ECBFC3F2E7DB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24187675980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24187675980.webp', 'https://www.flickr.com/photos/zaragozaantigua/24187675980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25709, 'Colegio Santa Rosa 1794', 'Plano del colegio a construir en los terrenos del convento de Santa Rosa. Pedro de Zeballos y Josâ”œآ® de Yarza, Zaragoza, 1794. El convento de Santa Rosa de las Misioneras Dominicas del Rosario, cuyos orâ”œآ،genes se remontan a 1674, comienza a ofrecer servicios educativos para niâ”œâ–’as en 1781. Pronto surge la necesidad de ampliar sus instalaciones mediante un nuevo edificio anexo, que refleja el plano, orientado de sur a norte. A la derecha, entrada principal desde la calle del Carmen. Arriba, pared recayente a la calle de San Jerâ”œâ”‚nimo. Abajo, accesos a la iglesia y convento. El solar que ocupaban convento, iglesia y colegio sigue ocupado parcialmente hoy por un moderno colegio de la misma Orden, entre la plaza de Salamero (antigua de Santa Fe) y las calles de Azoque y San Jerâ”œâ”‚nimo. Fuente visual: DARA/AHPZ.', 1794, 1794, 1794, 'Siglo XIX', 'CENTRO', 41.65183800, -0.88415300, '0101000020E61000001421753BFB4AECBF2025766D6FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24610753974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24610753974.webp', 'https://www.flickr.com/photos/zaragozaantigua/24610753974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25711, 'Calle San Ildefonso 1903', 'Calle de San Ildefonso, con la barroca iglesia del antiguo convento de San Ildefonso al fondo, redenominada en 1902 "Santiago el Mayor", heredando esa denominaciâ”œâ”‚n de la clausurada iglesia de Santiago de la calle Don Jaime I. Detrâ”œأ­s, el Hospital Militar. A la izquierda de la calle, inmediato, el taller de herrerâ”œآ،a mecâ”œأ­nica de Ramâ”œâ”‚n Vigata. A la derecha, viviendas de la calle, en el tramo entre las calles de Peromarta, y Arco de San Ildefonso. A la espalda del fotâ”œâ”‚grafo, la calle de Peromarta. Al fondo, hacia la izquierda, se abrâ”œآ،a la calle de la Biblioteca. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65303200, -0.88480800, '0101000020E610000044A7E7DD5850ECBFE99E758D96D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25467142845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25467142845.webp', 'https://www.flickr.com/photos/zaragozaantigua/25467142845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25714, 'Plaza Salamero 1972', 'Foto: Javier Torres. Vista, al fondo, del entorno de la plaza de Salamero desde lo que serâ”œأ­ la avenida de Câ”œآ®sar Augusto, en pleno proceso de derribo de la calle de Azoque y alrededores. Fuente: www.facebook.com/photo.php?fbid=166447690484841&set=g...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65243700, -0.88476600, '0101000020E6100000899B53C90050ECBFA5D93C0E83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30733963866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30733963866.webp', 'https://www.flickr.com/photos/zaragozaantigua/30733963866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25860, 'Teatro Fleta 2001', 'Aspecto del esqueleto del teatro Fleta de Zaragoza (1955) en 2001, tras su derribo para "remodelarlo". La previsiâ”œâ”‚n de reinauguraciâ”œâ”‚n estaba fijada en 2003. Fuente: Crâ”œâ”‚nica de Zaragoza. Ayuntamiento de Zaragoza, 2002.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18548452388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18548452388.webp', 'https://www.flickr.com/photos/zaragozaantigua/18548452388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25864, 'Teatro Fleta 2011', 'Panorâ”œأ­mica del solar del antiguo Teatro Fleta (1955), derribado para "remodelarlo" en el cambio de siglo, prevista su reinauguraciâ”œâ”‚n en 2003. A la derecha, avenida de Câ”œآ®sar Augusto. Fuente: www.andalan.es/?p=3881', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25528911076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25528911076.webp', 'https://www.flickr.com/photos/zaragozaantigua/25528911076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25867, 'Teatro Fleta 2009', 'Foto: Pedro Etura. Inusual vista urbana elevada tomada el 23 de enero de 2009 desde la avenida de Câ”œآ®sar Augusto, que muestra el esqueleto del Teatro Fleta, derribado en 2001 para "remodelarlo". Mâ”œأ­s al fondo, traseras de los edificios de la calle de Azoque y del paseo de la Independencia. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65166800, -0.88523800, '0101000020E610000076A565A4DE53ECBFC4EC65DB69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32116836154.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32116836154.webp', 'https://www.flickr.com/photos/zaragozaantigua/32116836154/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25869, 'Teatro Iris 1954', 'Imagen capturada en el vestâ”œآ،bulo del nuevo Teatro Iris, luego Teatro Fleta, con vista parcial del mural realizado por Francisco Javier Ciria Escartivol para decorar el irregular friso de 35 m sobre las puertas de ingreso al patio de butacas. Fue terminado a finales de 1954 con nueve paneles que destacaban por su descontextualizada temâ”œأ­tica relacionada con la denominada "pintura biolâ”œâ”‚gica" practicada por este autor, que en este caso muestra una interesante galerâ”œآ،a de animales de la fauna ibâ”œآ®rica, con representaciones de mamâ”œآ،feros como sarrios, cabras montesas, gamos y ciervos; aves como perdices, picarazas, abubillas, pitos verdes y una grulla. Ademâ”œأ­s, entre esta galerâ”œآ،a se incluyen dos mujeres. Tras el cierre del Teatro Fleta en 1999, las pinturas del mural fueron arrancadas en octubre de 2001 durante el proceso de "rehabilitaciâ”œâ”‚n" del teatro, para lo cual fue troceado en quince paneles y almacenado en la antigua Universidad Laboral de Zaragoza. En 2009 fueron trasladadas a las nuevas instalaciones de la Escuela Taller de Restauraciâ”œâ”‚n del Gobierno de Aragâ”œâ”‚n sita en PLAZA, donde se las restaurâ”œâ”‚ y almacenâ”œâ”‚ a la espera de que el Teatro Fleta sea rehabilitado... cuando sea. Las pinturas de la imagen se corresponden con los originales paneles nâ”¬â•‘ 6 y 7 (actuales nâ”¬â•‘ 9 y 10) de la zona central del mural, y en ellos aparecen las figuras de varios ciervos y de una mujer en dinâ”œأ­mica composiciâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65163100, -0.88523600, '0101000020E610000049BDA772DA53ECBFA70705A568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50652197202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50652197202.webp', 'https://www.flickr.com/photos/zaragozaantigua/50652197202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25925, 'Coso Alto c.1900', 'Imagen del primer tramo alto del Coso, posiblemente capturada desde la altura de la antigua Casa de las Monas, en cuyos bajos estaba la central interurbana de telâ”œآ®fonos. A la izquierda, la Audiencia y la calle homâ”œâ”‚nima. A la derecha, tramo del Coso entre la calle del Azoque y plaza de la Constituciâ”œâ”‚n. Sobre el firme, tendido de la tranviaria lâ”œآ،nea de Circunvalaciâ”œâ”‚n. Fuente visual: Fototipia Lucas Escolâ”œأ­ para ediciâ”œâ”‚n postal de la Uniâ”œâ”‚n Postal Universal, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65394400, -0.88361800, '0101000020E61000008E0585419946ECBF2DB5DE6FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34002372360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34002372360.webp', 'https://www.flickr.com/photos/zaragozaantigua/34002372360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21672, 'Sala de disecciâ”œâ”‚n c.1934', 'Foto: Colecciâ”œâ”‚n Josâ”œآ® Luis Cintora. Pabellâ”œâ”‚n de la sala de disecciâ”œâ”‚n del Hospital Provincial de Zaragoza, construida en 1873 y donde trabajaba Santiago Ramâ”œâ”‚n y Cajal. Se trata de las traseras del edificio, hoy calle Doctor Fleming. Fue demolido en 1958. Fuente: www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65125700, -0.88938700, '0101000020E6100000079ACFB9DB75ECBF4225AE635CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817786487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817786487.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817786487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21675, 'Enfermeras y ametralladora 1938', 'AHPZ. Estudio Coyne. Manuel Coyne. 1938. Zaragoza, como importantâ”œآ،sima ciudad de retaguardia en poder de los nacionalistas, se llenâ”œâ”‚ de hospitales en los que atender a los heridos del frente. En la imagen, enfermeras del Hospital Provincial de Zaragoza posando con niâ”œâ–’os junto a una ametralladora pesada Hotchkiss, colocada con funciones antiaâ”œآ®reas contra las incursiones de los aviones republicanos. En mayo de 1937, durante uno de los bombardeos, un par de bombas habâ”œآ،an caâ”œآ،do cerca del huerto del Hospital.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65223200, -0.88760700, '0101000020E6100000E86B96CB4667ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14839180729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14839180729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14839180729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21695, 'Iris Park c.1932', 'Propaganda del gran complejo Iris Park de Zaragoza, inaugurado en 1931, en la que se reproduce un dibujo de los edificios que lo componâ”œآ،an. Estaba situado entre las calles de Azoque y Ramâ”œâ”‚n y Cajal, sobre el trazado de la actual avenida de Câ”œآ®sar Augusto en su tramo del Teatro Fleta, que se construyâ”œâ”‚ en 1955 en el solar del Iris, recibiendo su nombre en un principio. Antes de la construcciâ”œâ”‚n de este centro de ocio (con, entre otras cosas, cine -el mâ”œأ­s grande de Zaragoza-, teatro y pista de patinaje), ocupaban el solar unos lavaderos pâ”œâ•‘blicos, con el Hospital Militar (antiguo convento de San Ildefonso) al norte, el Hospital Provincial al oeste y el Cuartel de Artillerâ”œآ،a al sur. Fuente: www.raimundolanas.com/vida.htm', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65171900, -0.88554200, '0101000020E61000007880272D5C56ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15358527522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15358527522.webp', 'https://www.flickr.com/photos/zaragozaantigua/15358527522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21949, 'Ramâ”œâ”‚n y Cajal 1949', '"Fachada del Hospital Provincial de Nuestra Seâ”œâ–’ora de Gracia de la Beneficencia de Zaragoza". En 1677 fue fundado el Hospital de Nuestra Seâ”œâ–’ora de la Piedad, llamado de Convalecientes por estar destinado a enfermos en proceso de curaciâ”œâ”‚n, y que precisaban "convalecer". Fue realizado en formas y maneras barrocas, junto a la resplandeciente iglesia de su interior. A mediados del XIX, ya bajo responsabilidad de la Diputaciâ”œâ”‚n Provincial, se realizaron obras para ampliar y mejorar las instalaciones hospitalarias, dâ”œأ­ndole el aspecto exterior que hoy conserva. En la imagen, aspecto del pabellâ”œâ”‚n situado a la izquierda de la iglesia, al que peatonalmente se accede desde la calle Ramâ”œâ”‚n y Cajal, y el trâ”œأ­fico rodado puede hacerlo por un paso a la izquierda. Tras el derribo del antiguo edificio de la Diputaciâ”œâ”‚n Provincial, el reloj que hasta entonces daba la hora desde su alabeado y caracterâ”œآ،stico frontâ”œâ”‚n superior, serâ”œأ­ migrado hasta el decorativo â”œâ”‚culo del frontâ”œâ”‚n que vemos. Fuente visual: www.bancodeimagenesmedicina.es/', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65177500, -0.88697400, '0101000020E6100000ADDF4C4C1762ECBFDAACFA5C6DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17186671109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17186671109.webp', 'https://www.flickr.com/photos/zaragozaantigua/17186671109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21905, 'Las Palmeras azules 1936', 'Imagen capturada en los pinares del cabezo de Buenavista inmediatos al "restaurant Las Palmeras" durante el almuerzo que el gremio de hoteleros obsequiâ”œâ”‚ a las 3.000 afiliadas a la Secciâ”œâ”‚n Femenina de Falange Espaâ”œâ–’ola de las JONS de Zaragoza y provincia (centurias de Calatayud, Tarazona, Borja, Ejea, Cariâ”œâ–’ena, Belchite, La Almunia, Pina y Sos), tras el homenaje "a los muertos de Espaâ”œâ–’a" y a "nuestra Santa Patrona la Virgen del Pilar" realizado el domingo 6 de septiembre de 1936. Dicho homenaje consistiâ”œâ”‚ en una marcial misa de campaâ”œâ–’a en el paseo de Pamplona, un desfile urbano de ida hasta el templo del Pilar que terminâ”œâ”‚ en la capilla de la "Virgen de Aragâ”œâ”‚n", y otro de regreso hasta la Facultad de Medicina y Ciencias. Hubo, ademâ”œأ­s, un homenaje en el cementerio de Torrero en la tumba de Marina Moreno, "la mâ”œأ­rtir" local de Falange. Durante la sobremesa del almuerzo hubo ocasiâ”œâ”‚n para una ilustrativa alocuciâ”œâ”‚n de Jesâ”œâ•‘s Muro, jefe provincial de Falange.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.63336600, -0.89310000, '0101000020E6100000DCD781734694ECBFFD32182312D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51728547058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51728547058.webp', 'https://www.flickr.com/photos/zaragozaantigua/51728547058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22122, 'Calle Padre Juan Bonal 1958', 'Desde 1873, en la Huerta Alta del Hospital Provincial, junto al paseo de la Ronda, funcionaba el "Anfiteatro, Sala de Disecciâ”œâ”‚n y Capilla para Cadâ”œأ­veres" del Hospital, donde trabajara un tiempo Santiago Ramâ”œâ”‚n y Cajal. En 1912 fueron construidos enfrente los Talleres del Hogar Pignatelli, y se abriâ”œâ”‚ un nuevo camino para conectar el paseo de la Ronda, y la calle de la Misericordia. En 1943, este camino recibiâ”œâ”‚ el nombre de Padre Juan Bonal (fundador de la Orden de las Hermanas de la Caridad de Santa Ana, cuya Casa General y Noviciado estaba cerca). En el momento de realizaciâ”œâ”‚n de la imagen, se estaba reurbanizando la zona, antes de construir la nueva Delegaciâ”œâ”‚n Provincial de Trabajo. Por ello, esta "Capilla para Cadâ”œأ­veres" (sin parroquia hace ya tiempo) y su reconocible â”œأ­bside semicircular, fueron demolidos integralmente. Al fondo, el paseo de Marâ”œآ،a Agustâ”œآ،n, con visual de los antiguos edificios de viviendas entre el cuartel de Trinitarios, y la calle de la Industria. A finales de 1960, este vial serâ”œآ،a redenominado "Doctor Fleming". Fuente visual: Jarke, Archivo Pâ”œâ•‘blico Municipal.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65158300, -0.88950600, '0101000020E610000099107349D576ECBF96D05D1267D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22727777828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22727777828.webp', 'https://www.flickr.com/photos/zaragozaantigua/22727777828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22385, 'Paseo de Marâ”œآ،a Agustâ”œآ،n c.1960', 'Aâ”œآ®rea imagen de la zona del paseo de Marâ”œآ،a Agustâ”œآ،n y la reurbanizada y ampliada nueva calle del Doctor Fleming. En primer tâ”œآ®rmino, ya ha sido derribado el antiguo "Anfiteatro, Sala de Disecciâ”œâ”‚n y Capilla para Cadâ”œأ­veres" del Hospital Provincial. Allâ”œآ، se levantarâ”œأ­ despuâ”œآ®s la nueva sede de la Delegaciâ”œâ”‚n Provincial de Trabajo. Enfrente, los Talleres del Hogar Pignatelli, y los nuevos bloques para funcionarios. En primerâ”œآ،simo plano, a la izquierda, el cuartel de Trinitarios. Arriba, a la izquierda, el cuartel del Cid. Ademâ”œأ­s: el Coso de la Misericordia, el Hogar Pignatelli, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, la Huerta del Hospital Provincial, el Cuartel de Sangenis, el Parque de Artillerâ”œآ،a, la plaza del Portillo... Fuente visual: "Los talleres del Hogar Pignatelli".', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22525920433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22525920433.webp', 'https://www.flickr.com/photos/zaragozaantigua/22525920433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22504, 'Calle del Doctor Fleming 1960', 'Imagen aâ”œآ®rea de la zona donde habâ”œآ،an sido construidos los cuatro nuevos bloques de viviendas para funcionarios junto al paseo de Marâ”œآ،a Agustâ”œآ،n, en terrenos del Hospicio y Hospital Provincial. La reurbanizaciâ”œâ”‚n de este entorno propiciâ”œâ”‚ tambiâ”œآ®n la apertura de la nueva calle del Doctor Fleming, en primer tâ”œآ®rmino, como conexiâ”œâ”‚n râ”œأ­pida entre la de Madre Rafols y el paseo. Destacan los restos del antiguo Anfiteatro, Sala de Disecciâ”œâ”‚n y Capilla para Cadâ”œأ­veres del Hospital Provincial, frente a los Talleres del Hogar Pignatelli. Al otro lado del paseo perduran los restos del cuartel de Trinitarios. En la parte superior, el Grupo escolar Joaquâ”œآ،n Costa, el Refugio, el cuartel de la Policâ”œآ،a Armada y la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, donde destaca el gran depâ”œâ”‚sito de locomotoras de vapor. A la derecha, la triangular manzana de viviendas militares entre el paseo de Marâ”œآ،a Agustâ”œآ،n y la avenida de Anselmo Clavâ”œآ®. Frente a ellas, el Hogar Pignatelli, y en la parte inferior y a la derecha la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, con su gran zona de jardines. Entre los planes para esta zona constaba el proyecto de una gran plaza con jardines "para embellecer la entrada a la ciudad por la estaciâ”œâ”‚n del Mediodâ”œآ،a (sic)". La fijaciâ”œâ”‚n por "embellecer" la ciudad incluâ”œآ،a cambiar el nombre de la veterana estaciâ”œâ”‚n de Campo Sepulcro, tal vez por su mortuoria referencia. Mientras tanto, el parque previsto no pasarâ”œآ،a de las musas al teatro de la realidad.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65185500, -0.89018200, '0101000020E6100000A69C2FF65E7CECBFF65D11FC6FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50045877448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50045877448.webp', 'https://www.flickr.com/photos/zaragozaantigua/50045877448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22570, 'Câ”œâ”‚lera 1971', 'Fila para vacunaciâ”œâ”‚n del câ”œâ”‚lera en la Jefatura Provincial de Sanidad, en la calle de Ramâ”œâ”‚n y Cajal nâ”¬â•‘ 68. En los aâ”œâ–’os setenta aparecieron varias epidemias de câ”œâ”‚lera en Espaâ”œâ–’a, la primera de las cuales afectâ”œâ”‚ en 1971 a Zaragoza, Barcelona, Valencia y Murcia. Como consecuencia, hubo una epidemia (positiva) de inversiones y actuaciones pâ”œâ•‘blicas para mejorar la calidad del agua corriente y el alcantarillado en los barrios obreros de la periferia.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65118200, -0.88655500, '0101000020E6100000745E6397A85EECBF37DF88EE59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15326736006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15326736006.webp', 'https://www.flickr.com/photos/zaragozaantigua/15326736006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22601, 'Vâ”œآ،a Imperial 1973', '"En esta zona se construirâ”œأ­ un gran aparcamiento subterrâ”œأ­neo", foto Monge, 1973. El aparcamiento al que se refiere el titular "ocuparâ”œأ­ la zona que queda sin urbanizar del Plan Parcial Especial de San Ildefonso. Abarcarâ”œأ­ desde el cruce entre General Sanjurjo y Capitâ”œأ­n Portolâ”œآ®s hasta la zona situada ante la iglesia de Santiago actual salida a la plaza de Salamero por la Vâ”œآ،a Imperial". En la imagen, a la izquierda, el hotel Corona de Aragâ”œâ”‚n; a la derecha, el teatro Fleta; al fondo, torreâ”œâ”‚n derecho del antiguo palacio de Luna-Morata, o Audiencia. Fuente: Diario Amanecer, 11 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65194200, -0.88548400, '0101000020E61000005133A48AE255ECBFC571E0D572D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18753121924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18753121924.webp', 'https://www.flickr.com/photos/zaragozaantigua/18753121924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22698, 'Nocturna San Ildefonso 1971', 'Nocturna imagen, desde cierta altura, del entorno del Hospital Provincial, la calle Ramâ”œâ”‚n y Cajal, y la iglesia parroquial de San Ildefonso. Al fondo, el reflejo selenita del sol, en una toma irrepetible poco despuâ”œآ®s, cuando a la plaza de Salamero, antigua de Santa Fe, le crezca un referencial y palmario rascacielos. A la izquierda, entre tinieblas, la linterna que culmina la câ”œâ•‘pula de la barroca iglesia del antiguo hospital de convalencientes, levantada allâ”œأ­ por el siglo diez y siete. Fuente visual: Patti Larson Photo, en www.flickr.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65183300, -0.88713400, '0101000020E6100000E36DA5D76663ECBF0FBA84436FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27366926373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27366926373.webp', 'https://www.flickr.com/photos/zaragozaantigua/27366926373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23106, 'Fernando Arrabal 2000', 'El escritor melillense Fernando Arrabal (1932), ante uno de sus retratos, pintados por diversos autores y expuestos en el museo Pablo Serrano en febrero de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24523279782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24523279782.webp', 'https://www.flickr.com/photos/zaragozaantigua/24523279782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23149, 'Calle Albareda 2009', 'Foto: Juan Carlos Arcos. Construcciâ”œâ”‚n en febrero de 2009 del nuevo edificio de la sede del Ministerio de Economâ”œآ،a, en la calle de Josâ”œآ® Luis Albareda 18, junto a la Delegaciâ”œâ”‚n de Hacienda. Las obras se iniciaron en 2005 y concluyeron en noviembre de 2009. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65161200, -0.88837100, '0101000020E6100000C6DFF604896DECBF30D7A20568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32167848144.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32167848144.webp', 'https://www.flickr.com/photos/zaragozaantigua/32167848144/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23175, 'Gran Teatro Fleta 2004', 'Imagen de la fachada del Gran Teatro Fleta, en la avenida de Câ”œآ®sar Augusto, con los andamios de obra y el cartelâ”œâ”‚n del proyecto que, entre 2001 y 2003, tras el derribo parcial de sus instalaciones y su vaciado interno, y con el lema "sin lâ”œآ،mites a la creatividad", fue impulsado por el Gobierno de Aragâ”œâ”‚n para convertirlo en sede del Centro Dramâ”œأ­tico Aragonâ”œآ®s, de la futura Orquesta Sinfâ”œâ”‚nica de Aragâ”œâ”‚n, y aun de la â”œأ´pera de Aragâ”œâ”‚n, con el respaldo financiero (por eso figuran sus logos) de las dos grandes cajas de ahorros locales de la â”œآ®poca. Este proyecto quedâ”œâ”‚ varado en 2003, fecha prevista para finalizar la remodelaciâ”œâ”‚n anunciada, y tambiâ”œآ®n fecha lâ”œآ،mite de la autorizaciâ”œâ”‚n para mantener los andamios de la imagen. En 2013, tras algunos otros interesantes proyectos de papel y/o virtuales para el edificio, y cartelones para la fachada, los andamios fueron finalmente retirados, tras restaurar la fachada con referencia a la que fuera original de Yarza Garcâ”œآ،a, que desde entonces ejerce de desnudo telâ”œâ”‚n tras el que perdura un espacio que sigue en barbecho. Fuente visual: apudepa.blogia.com/', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65166000, -0.88547400, '0101000020E61000006DAAEE91CD55ECBF410E4A9869D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34160586425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34160586425.webp', 'https://www.flickr.com/photos/zaragozaantigua/34160586425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23634, 'Visita de Alfonso XII 1882', 'A.M.Z. Sign. 0908. Monumentos conmemorativos con motivo de la visita del rey Alfonso XII y su esposa la reina Cristina de Habsburgo a Zaragoza. Tres engalanamientos para Zaragoza ante la visita del rey Borbâ”œâ”‚n y su esposa, Cristina de Habsburgo. El primero, un Arco de Triunfo sito en el paseo de Santa Engracia; el segundo, en la entrada del hospicio Provincial y el tercero, ornato neoarâ”œأ­bigo en la puerta de un cuartel sin identificar.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.65365100, -0.89044800, '0101000020E6100000473CD9CD8C7EECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672229740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672229740.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672229740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23923, 'Cuartel de Sangenis 1963', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Agosto 1963. "Vista general de una edificaciâ”œâ”‚n." Concretamente, se trata del Centro de Especialidades "Ramâ”œâ”‚n y Cajal", a la derecha, junto al Paseo de Marâ”œآ،a Agustâ”œآ،n. A su izquierda se levantarâ”œأ­, tres aâ”œâ–’os despuâ”œآ®s, la Delegaciâ”œâ”‚n Provincial de Trabajo. Mientras tanto, desde la altura del alto bloque de viviendas inmediato a los antiguos talleres de oficios del hospicio provincial, u Hogar Pignatelli, podemos contemplar una buena perspectiva del inmenso Cuartel de Sangenis, o de Pontoneros, y el Hospital de Nuestra Seâ”œâ–’ora de Gracia. A la izquierda, por encima de los tejados sobresale la cupulilla de la iglesia de los Escolapios.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65246500, -0.88831500, '0101000020E6100000CC7A3194136DECBF6F641EF983D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033159208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033159208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033159208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24056, 'Avenida Câ”œآ®sar Augusto 2005', 'Foto: Juan Carlos Arcos. 11 de octubre de 2005. Un elefante asiâ”œأ­tico del Circo Mundial desayuna frutas y verduras junto al hotel Meliâ”œأ­ Zaragoza. A la derecha, grâ”œâ•‘a y andamios de la obra de remodelaciâ”œâ”‚n/demoliciâ”œâ”‚n del Teatro Fleta, paralizada en 2003. En 2013, ante la prolongada situaciâ”œâ”‚n de parâ”œأ­lisis, el andamio fue retirado. Y en 2015, los circos con animales dejaron de visitar la ciudad. Fuente: Heraldo de Aragâ”œâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65138400, -0.88609400, '0101000020E610000081D1E5CDE15AECBF9F91088D60D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31674976752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31674976752.webp', 'https://www.flickr.com/photos/zaragozaantigua/31674976752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24074, 'Palacio de Cristal 1931', 'Imagen de la suntuosa fachada del Palacio de Cristal, sito en el recinto del Iris Park, con entrada principal por la calle de Ramâ”œâ”‚n y Cajal. Su denominaciâ”œâ”‚n venâ”œآ،a dada porque en sus altas paredes se abrâ”œآ،a una enorme cantidad de ventanales y vidrieras, lo que le convertâ”œآ،a en un escenario â”œâ•‘nico para la celebraciâ”œâ”‚n de diversos eventos festivos con gran afluencia de pâ”œâ•‘blico. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65166000, -0.88547400, '0101000020E61000006DAAEE91CD55ECBF410E4A9869D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36610510405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36610510405.webp', 'https://www.flickr.com/photos/zaragozaantigua/36610510405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24516, 'Lavadero de Castellvâ”œآ، 1931', 'Imagen capturada desde cierta altura con el panorama del lavadero de Castellvâ”œآ، al poco tiempo de su cierre. Su enorme extensiâ”œâ”‚n, sobre todo para la zona de secadero de ropa al aire, estaba delimitada por las calles de Ramâ”œâ”‚n y Cajal, de la Soberanâ”œآ،a Nacional, y del Azoque. En la imagen, a la izquierda, parte del antiguo hospital Militar anexo a la iglesia de Santiago. Al fondo, traseras de edificios de vivienda recayentes a la calle de la Biblioteca, y a la del Azoque. Sobre este solar se levantarâ”œآ،a, poco despuâ”œآ®s, el complejo recreativo del Iris Park, inaugurado ese mismo aâ”œâ–’o. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65166000, -0.88547400, '0101000020E61000006DAAEE91CD55ECBF410E4A9869D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35180440752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35180440752.webp', 'https://www.flickr.com/photos/zaragozaantigua/35180440752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24875, 'Piscina y torres 1970', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1970. Desde la piscina del nuevo Hotel Corona de Aragâ”œâ”‚n las vistas son tremendas. En la imagen, sin pretenderlo, despuntan el remate de la câ”œâ•‘pula de Santiago el Mayor, el torreâ”œâ”‚n del Banco de Aragâ”œâ”‚n, la torre de la Seo y su cimborrio, San Gil... Y abajo, la nueva avenida de Câ”œآ®sar Augusto.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65146200, -0.88622800, '0101000020E6100000689599D2FA5BECBF1B4B581B63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753647307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753647307.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753647307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24896, 'Delegaciâ”œâ”‚n Provincial de Trabajo 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho 24/12/1966. Antigua Delegaciâ”œâ”‚n Provincial de Trabajo de Zaragoza, en la calle Doctor Fleming con vistas a Marâ”œآ،a Agustâ”œآ،n, desde donde estâ”œأ­ hecha la foto. El edificio acaba de ser inaugurado, formando un conjunto con el del Hospital Ramâ”œâ”‚n y Cajal, ambos del arquitecto Fernando Garcâ”œآ،a Mercadal. Al fondo a la izquierda, torre de San pablo. A la derecha, detrâ”œأ­s del Hospital de Nuestra Seâ”œâ–’ora de Gracia, la câ”œâ•‘pula de la iglesia de Santiago.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65125700, -0.88938700, '0101000020E6100000079ACFB9DB75ECBF4225AE635CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211673115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211673115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211673115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25472, 'Propiedades de la Diputaciâ”œâ”‚n 1953', 'Plano de edificios y terrenos propiedad de la Diputaciâ”œâ”‚n de Zaragoza, noviembre de 1953. Fuente: Archivo DPZ.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65277600, -0.88973200, '0101000020E6100000AC8C463EAF78ECBF8ECEF9298ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24313701002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24313701002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24313701002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25488, 'P.â”¬â•‘ de Marâ”œآ،a Agustâ”œآ،n c.1961', 'Imagen capturada posiblemente desde la altura del nâ”¬â•‘ 9 del paseo de Marâ”œآ،a Agustâ”œآ،n, esquinero con la calle del Capitâ”œأ­n Esponera, con una interesante vista parcial de la zona delimitada entre el paseo, la nueva calle del Doctor Fleming y el Hogar Pignatelli. En primer tâ”œآ®rmino, huerta de las MM. Carmelitas de la Encarnaciâ”œâ”‚n y del Hospital Provincial. En el centro, edificios inmediatos al ya derribado Anfiteatro, Sala de Disecciâ”œâ”‚n y Capilla para Cadâ”œأ­veres del Hospital Provincial. Enfrente, Talleres del Hogar Pignatelli y los modernos y rectangulares bloques edilicios para funcionarios. Tras ellos, el Hogar Pignatelli y, parcialmente, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana. Al fondo del paseo, el Grupo Escolar Joaquâ”œآ،n Costa y las viviendas para militares de la confluencia con Anselmo Clavâ”œآ®.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65118400, -0.88954800, '0101000020E6100000541C075E2D77ECBFD8D64FFF59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43601516425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43601516425.webp', 'https://www.flickr.com/photos/zaragozaantigua/43601516425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25701, 'Sala de disecciâ”œâ”‚n 1873', '"Plano general de la huerta alta del hospital provincial, planta, alzado y secciones del Anfiteatro Sala de disecciâ”œâ”‚n y capilla para cadâ”œأ­veres", Julio Ferrâ”œأ­n, Zaragoza, 1873. En las inmediaciones del Hospital Provincial se levantâ”œâ”‚ este pequeâ”œâ–’o edificio en 1873, con su teatro anatâ”œâ”‚mico y su capilla. En â”œآ®l trabajâ”œâ”‚ Santiago Ramâ”œâ”‚n y Cajal. Fue demolido en 1958. El plano general (abajo) estâ”œأ­ orientado de sur a norte, con el paseo de la Ronda (hoy Marâ”œآ،a Agustâ”œآ،n) indicado arriba. La ubicaciâ”œâ”‚n actual serâ”œآ،a la calle del Doctor Fleming, en su tramo mâ”œأ­s cercano al paseo. Fuente: Archivo DPZ.', 1873, 1873, 1873, 'Siglo XIX', 'CENTRO', 41.65158300, -0.88950600, '0101000020E610000099107349D576ECBF96D05D1267D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785140679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785140679.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785140679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26058, 'Vista aâ”œآ®rea Vâ”œآ،a Imperial c.1969', 'Vista aâ”œآ®rea centrada en la Vâ”œآ،a Imperial, con la Puerta del Carmen abajo y el Teatro Fleta en el centro. Al fondo, el Coso Alto. Fuente visual: foto Pedro Marco.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65145900, -0.88595700, '0101000020E61000005531957EC259ECBFAAD72D0263D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33569037491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33569037491.webp', 'https://www.flickr.com/photos/zaragozaantigua/33569037491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23018, 'Pl. del Ecce Homo c.1998', 'Imagen capturada en la plaza del Ecce Homo y centrada en los abandonados edificios de los nâ”œâ•‘meros 6 y 7 de ese vial, inmediatos a la imprenta de Tomâ”œأ­s Blasco (nâ”¬â•‘ 8). A la izquierda, solares de los ya derribados nâ”œâ•‘meros 5 y 4, esquinero â”œآ®ste â”œâ•‘ltimo con la calle de Galo Ponte, antigua de la Audiencia. Enfrente a todos ellos, vista parcial de los andamios de remodelaciâ”œâ”‚n del nâ”¬â•‘ 3 como nueva sede de la Escuela Universitaria de Turismo de Zaragoza (ETUZ). Fuente visual: AMZ.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.65467100, -0.88301400, '0101000020E6100000E61F7D93A641ECBFDF516342CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40710585122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40710585122.webp', 'https://www.flickr.com/photos/zaragozaantigua/40710585122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23132, 'Plaza Ecce Homo 2007', 'Foto: Juan Carlos Arcos. Vista del edificio de la Imprenta Blasco, en la plaza del Ecce Homo 8, esquina con la calle del Paraâ”œآ،so (derecha), en octubre de 2007. Este inmueble con ornamentos neogâ”œâ”‚ticos fue levantado en dos fases, segâ”œâ•‘n proyecto de Teodoro Râ”œآ،os: en 1924 (fachada a Ecce Homo) y en 1938 (chaflâ”œأ­n y ala derecha). Fue adquirido por el Ayuntamiento en 2002, con la intenciâ”œâ”‚n de que albergase un museo de la imprenta. El bloque de la derecha fue derribado ese mismo mes. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65466600, -0.88321000, '0101000020E61000005001309E4143ECBFCDE67118CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31694772074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31694772074.webp', 'https://www.flickr.com/photos/zaragozaantigua/31694772074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21231, 'Muralla medieval 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 35, Zaragoza 1908 - Centenario de los Sitios", 1907. "Tapia aspillerada de San Agustâ”œآ،n. Siendo el convento de San Agustâ”œآ،n uno de los puntos mâ”œأ­s atacados desde las baterâ”œآ،as francesas inmediatas al Huerva, los altos muros que cercaban su huerta, fueron aspillerados para la defensa de toda aquella parte de la ciudad, por donde los invasores intentaron repetidamente su entrada." Trenque en la muralla medieval, actualmente conservado entre los nâ”œâ•‘meros 53 y 55 de la calle Asalto de Zaragoza. En el momento de tomar la foto, el lugar correspondâ”œآ،a a las traseras del convento de las Capuchinas. Fuente: www.pasapues.es/antiguas/exposicion1908/zaragoza190835.php', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64925000, -0.87275800, '0101000020E6100000D7506A2FA2EDEBBFC976BE9F1AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19240864666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19240864666.webp', 'https://www.flickr.com/photos/zaragozaantigua/19240864666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21318, 'Calle La Torre 1908', 'Calle de La Torre, en su entonces â”œâ•‘ltimo tramo, bajando hasta la de Manuela Sancho, en la que terminaba. El edificio de la izquierda es la fâ”œأ­brica de Averly, Montaut y Garcâ”œآ،a, con razâ”œâ”‚n social en las calles de La Torre 23 y Manuela Sancho 27. Su propietario â”œâ•‘nico en 1908 era Josâ”œآ® Garcâ”œآ،a Dâ”œآ،az, y producâ”œآ،a telas metâ”œأ­licas, ademâ”œأ­s de comercializar piedras de molino importadas de Francia. La compaâ”œâ–’â”œآ،a se habâ”œآ،a constituido en 1877, con Antonio Averly como socio, pero ya en 1880 â”œآ®ste trasladâ”œâ”‚ sus actividades a la Fundiciâ”œâ”‚n Averly de Campo Sepulcro. Fuente visual: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64958300, -0.87334800, '0101000020E610000040DD408177F2EBBFCF84268925D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40482429784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40482429784.webp', 'https://www.flickr.com/photos/zaragozaantigua/40482429784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21445, 'Calle de La Torre c.1912', 'Imagen capturada en el â”œâ•‘ltimo tramo de la calle de la Torre (antigua de la Subida del Gato) y centrada en el soleado inmueble del nâ”¬â•‘ 23, esquinero con el nâ”¬â•‘ 27 de la calle de Manuela Sancho (antigua del Pabostre), donde estaba radicada desde 1877 la fâ”œأ­brica de piedras de molino y telas metâ”œأ­licas de Averly, Montaut y Garcâ”œآ،a, que desde 1903 era propiedad en solitario de Josâ”œآ® Garcâ”œآ،a Dâ”œآ،az. Un carro tirado por caballerâ”œآ،a carga unos metros lineales de tela metâ”œأ­lica, mientras los trajineros posan en la puerta de la factorâ”œآ،a. Destaca el final de la calle de la Torre, que desemboca en la de Manuela Sancho, cuyos inmuebles nâ”¬â•‘ 32-34 figuran al fondo. Tras siglos con este trazado urbanâ”œآ،stico, tiempo despuâ”œآ®s la calle de la Torre serâ”œآ،a prolongada hasta la calle del Asalto, cuyos â”œأ­rboles emergen levemente sobre el horizonte.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64957900, -0.87335900, '0101000020E61000003A5AD5928EF2EBBF8E95986725D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49949988797.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49949988797.webp', 'https://www.flickr.com/photos/zaragozaantigua/49949988797/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21447, 'Calle de Manuela Sancho c.1912', 'Imagen capturada en la calle de Manuela Sancho y centrada en inmueble del nâ”¬â•‘ 27, esquinero con la calle de la Torre, donde estaba radicada la fâ”œأ­brica de piedras de molino y telas metâ”œأ­licas de Averly, Montaut y Garcâ”œآ،a. La escena representa la maniobra de carga mediante polea de una piedra de molino en un carro. A la derecha y fuera de plano se encontraba el convento de las capuchinas. Hacia el fondo, la calle curvea hasta la plazuela de las Eras, pasando por la calle de las Eras y la de Alcalâ”œأ­.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64946600, -0.87320900, '0101000020E6100000E754320054F1EBBF95EEAEB321D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49955288947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49955288947.webp', 'https://www.flickr.com/photos/zaragozaantigua/49955288947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21824, 'Râ”œآ،o Huerva 1933', 'Aspecto del râ”œآ،o Huerva durante la crecida de principios del mes de junio, a su paso por la calle del Asalto, en una imagen capturada desde el puente de San Josâ”œآ®. A la izquierda, muros traseros del Corral de Abastos de Intendencia militar. Al fondo, tras la chimenea de la central de Elâ”œآ®ctricas Reunidas de Zaragoza, y el Cuartel de la Tercera Comandancia de Intendencia. Hemos introducido una referencia aproximada, en distintivo color verde, a la lâ”œآ،nea de la antigua ribera que el desbordamiento de caudal se llevâ”œâ”‚ consigo aguas abajo, hasta el Ebro. Fuente visual: foto Palacio, en "Diario Ahora" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64833000, -0.87339500, '0101000020E61000006DAD2F12DAF2EBBF0282397AFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32191582830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32191582830.webp', 'https://www.flickr.com/photos/zaragozaantigua/32191582830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22205, 'Calle de la Torre 1951', 'Despejada imagen de la adoquinada calle de la Torre capturada desde su desemboque en descenso en la calle de Manuela Sancho (antigua del Pabostre), donde originalmente terminaba. A la derecha, en la que fuera zona de las Eras de San Agustâ”œآ،n, fachadas de los desaparecidos inmuebles de los nâ”œâ•‘meros 23, 21, 19 y 17. Al fondo, el desaparecido nâ”¬â•‘ 16, camino al arranque de esta calle desde la de Cantâ”œآ،n y Gamboa. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64953300, -0.87336800, '0101000020E610000007EFAB72A1F2EBBF1D56B8E523D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38244734061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38244734061.webp', 'https://www.flickr.com/photos/zaragozaantigua/38244734061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22819, 'Calle del Asalto 1973', 'Inâ”œآ®dita imagen capturada en la calle del Asalto a la altura de las traseras del convento de las Madres clarisas capuchinas que entre 1877 y 1973 estuvo ubicado en la calle de Manuela Sancho. El amplio terreno de ese convento fue vendido al mejor postor, que tras el preceptivo derribo promoviâ”œâ”‚ la construcciâ”œâ”‚n de unos modernos bloques de viviendas. El muro perimetral recayente a la calle del Asalto, resto de la antigua muralla de ladrillo y adobe levantada en tiempos de la Saraqusta musulmana, y reforzada posteriormente, presenta una lâ”œأ­pida instalada en 1908 a instancias del Ayuntamiento que recuerda que durante los asedios de 1808-1809 aquâ”œآ، estuvo ubicada la "baterâ”œآ،a alta de Palafox", posiciâ”œâ”‚n artillera donde encontrâ”œâ”‚ la muerte el comandante de ingenieros militares Antonio Sangenis. Este hecho preservâ”œâ”‚ milagrosamente este muro del integral derribo de todas las dependencias conventuales. Al fondo y a la derecha sobresale el moderno bloque incrustado en la manzana entre la calle de Manuela Sancho, la plaza de las Eras y la calle de Alcalâ”œأ­, y que poco despuâ”œآ®s serâ”œآ،a eclipsado por los bloques aquâ”œآ، construidos. En primer tâ”œآ®rmino, un Seat 1500 en su popular versiâ”œâ”‚n como taxi.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64912200, -0.87262900, '0101000020E6100000615111A793ECEBBF9B8E006E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51622307225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51622307225.webp', 'https://www.flickr.com/photos/zaragozaantigua/51622307225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22893, 'Canâ”œâ”‚dromo c.1982', 'Foto del canâ”œâ”‚dromo de Zaragoza en los aâ”œâ–’os 80. Estaba situado en Miguel Servet 1, interior: el actual parque de Villafeliche, vulgo del Canâ”œâ”‚dromo, en la calle de Salvador de Madariaga, junto al râ”œآ،o Huerva. Al fondo se puede ver la torre de la iglesia de San Miguel.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64836000, -0.87435700, '0101000020E6100000E2EA0088BBFAEBBF6C04E275FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20424249245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20424249245.webp', 'https://www.flickr.com/photos/zaragozaantigua/20424249245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23058, 'Parque de Villafeliche 1994', 'A mediados de la dâ”œآ®cada de los noventa se llevâ”œâ”‚ a cabo la transformaciâ”œâ”‚n de la ribera del râ”œآ،o Huerva a su paso por Zaragoza en un corredor verde denominado Parque Lineal del Râ”œآ،o Huerva, un proyecto global que sumaba una serie de parques entre los que se encuentra el llamado parque de Villafeliche, trazado donde estuviera el antiguo Canâ”œâ”‚dromo. En la imagen, tareas de limpieza en una captura de esta zona donde al fondo y a la izquierda se destaca el inmueble de la calle de la Torre esquinero con la del Asalto. A la derecha, las instalaciones de ERZ-Endesa y el Hâ”œأ­bitat Don 2000.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64860800, -0.87390600, '0101000020E6100000D1E638B709F7EBBF45F6419605D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50451149326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50451149326.webp', 'https://www.flickr.com/photos/zaragozaantigua/50451149326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24975, 'Vivero de la Puerta Quemada 1865', 'Plano del vivero de la Puerta Quemada, Antonio Berbegal, Zaragoza, 1865. Aspecto de la plantaciâ”œâ”‚n municipal de acacias y olmos en el solar triangular de los viveros municipales de la Puerta Quemada, en 1920 ferial de ganado, luego almacâ”œآ®n de intendencia del ejâ”œآ®rcito "Corral de la Leâ”œâ–’a", y actual parque del mismo nombre (antes "de la Mancomunidad de Aragâ”œâ”‚n"), primera actuaciâ”œâ”‚n de la "Operaciâ”œâ”‚n cuarteles", en 1975. Arriba, el entonces paseo de la Mina, hoy calle de Asalto. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64879200, -0.87238400, '0101000020E61000009EB7B1D991EAEBBF06F4C29D0BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20411112124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20411112124.webp', 'https://www.flickr.com/photos/zaragozaantigua/20411112124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20924, 'Convento de San Francisco hacia 1500', '"Das Franziskaner Kloster in Saragossa", fotografâ”œآ،a realizada por Max Skladanowsky hacia 1890, coloreada luego a mano, en la que captura un dibujo de autor desconocido que pretende recrear el hipotâ”œآ®tico claustro del Real convento de San Francisco de Zaragoza, situado entre la estrecha calle del Hospital y el Coso de Carabaceros. La nostalgia del pasado medieval, impostada como tendencia intelectual decimonâ”œâ”‚nica en Europa, derivâ”œâ”‚ en la "recuperaciâ”œâ”‚n" virtual de elementos arquitectâ”œâ”‚nicos desaparecidos del medievo, como este convento levantado en el siglo XIII, con posteriores e importantes reformas y ampliaciones, que fue muy afectado por los conflictos bâ”œآ®licos de 1808-1809, y cuya enorme extensiâ”œâ”‚n luego fue, bien vendida a particulares, bien convertida en solar sobre el que construir las dependencias de la Diputaciâ”œâ”‚n Provincial. Los hermanos Skladanowsky (este Max, y Emil), fueron los pioneros del cine en Alemania con su proyector "Bioskop" en 1895, en el Teatro "Wintergarten" de Berlâ”œآ،n, unas semanas antes que otros hermanos franceses, de apellido Lumiâ”œآ؟re, hicieran lo propio en el Gran Cafâ”œآ® de Parâ”œآ،s. Fuente visual: www.bild.bundesarchiv.de/', 1500, 1500, 1500, 'Siglo XIX', 'CENTRO', 41.65247300, -0.88168500, '0101000020E6100000D8F50B76C336ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20547463171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20547463171.webp', 'https://www.flickr.com/photos/zaragozaantigua/20547463171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21013, 'Coso Medio 1860', 'Recreaciâ”œâ”‚n estilizada del templete o torreâ”œâ”‚n â”œأ­rabe erigido con motivo de la visita de la reina Isabel II a la ciudad. Fuente: www.mecd.gob.es/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18835474358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18835474358.webp', 'https://www.flickr.com/photos/zaragozaantigua/18835474358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21021, 'Pl. de la Constituciâ”œâ”‚n 1868', 'Grabado de Urrabieta en el que se representa una manifestaciâ”œâ”‚n de zaragozanas contra el reclutamiento de las quintas con destino a â”œأ¼frica, ante el edificio de la Diputaciâ”œâ”‚n Provincial de Zaragoza. En carteles y banderas se puede leer: "Abajo las quintas", "Abajo los Borbones" y "Repâ”œâ•‘blica Federal Sufragista". Fuente: www.akg-images.co.uk/', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20689438908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20689438908.webp', 'https://www.flickr.com/photos/zaragozaantigua/20689438908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21065, 'Amadeo I 1871', 'Mariano Jâ”œâ•‘dez. 1871. Imagen de Amadeo I, italiano rey de Espaâ”œâ–’a entre 1870 y 1873, realizada en el gabinete fotogrâ”œأ­fico de Mariano Jâ”œâ•‘dez y Ortiz en el Coso, 33, â”œâ•‘ltimo piso, durante la visita Real a Zaragoza los dâ”œآ،as 26-28 de setiembre de 1871. Fuente: "Primeros tiempos de la fotografâ”œآ،a en Zaragoza" (2010).', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65295400, -0.88154500, '0101000020E610000068791EDC9D35ECBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15693157239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15693157239.webp', 'https://www.flickr.com/photos/zaragozaantigua/15693157239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21159, 'Palacio de Coloma 1898', 'Fachada de la antigua casa palacio de Juan de Coloma (1539), segâ”œâ•‘n proyecto de Juan de la Mica. Serâ”œأ­ la nueva sede del Casino Mercantil y Agrâ”œآ،cola cuando. tras su derribo en 1912, se construya un nuevo edificio con diseâ”œâ–’o de Francisco Albiâ”œâ–’ana, en el Coso 29 de Zaragoza. Fuente visual: La Revista Moderna, 26 de noviembre de 1898.', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20035192555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20035192555.webp', 'https://www.flickr.com/photos/zaragozaantigua/20035192555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21169, 'Centro Mercantil 1898', 'Imagen capturada en el interior del Salâ”œâ”‚n de Fiestas del Centro Mercantil, Industrial y Agrâ”œآ،cola de Zaragoza, que fuera antigua casa de Juan Coloma, y luego de los Pâ”œآ®rez de Pomar, del conde de Guimerâ”œأ­, del duque de Hâ”œآ،jar, y finalmente de Azara (marquâ”œآ®s de Nibbiano). Este esplendoroso Salâ”œâ”‚n de Fiestas, que habâ”œآ،a sido remodelado recientemente por el maestro de obras Antonio Miranda, lucâ”œآ،a de esta guisa antes del inicio de la Iâ”¬آ¬ Asamblea de Câ”œأ­maras de Comercio, Industria y Navegaciâ”œâ”‚n de Espaâ”œâ–’a, bajo la presidencia de Basilio Paraâ”œآ،so. Fuente visual: fotografâ”œآ،a de Enrique Beltrâ”œأ­n editada por Josep Thomas, en revista La Ilustraciâ”œâ”‚n Artâ”œآ،stica (Barcelona).', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65276600, -0.88151300, '0101000020E610000090F63FC05A35ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26804517708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26804517708.webp', 'https://www.flickr.com/photos/zaragozaantigua/26804517708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21172, 'Casa de Coloma 1898', 'Fachada de la antigua casa de Juan de Coloma, construida en el Coso alto durante el primer tercio del siglo XVI, segâ”œâ•‘n proyecto de Juan de la Mica. Serâ”œأ­ la nueva sede del Casino Mercantil, Industrial y Agrâ”œآ،cola cuando, tras su derribo, se construya un nuevo edificio con diseâ”œâ–’o de Francisco Albiâ”œâ–’ana. La imagen se ha tomado con motivo de la celebraciâ”œâ”‚n en Zaragoza de la asamblea estatal de Câ”œأ­maras de Comercio que tuvo lugar en noviembre de 1898 en este singular espacio. Fuente visual: revista "Nuevo mundo", 30 de noviembre de 1898.', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30249628504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30249628504.webp', 'https://www.flickr.com/photos/zaragozaantigua/30249628504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21330, 'Calle de la Independencia 1903', 'Efâ”œآ،mero arco triunfal patrocinado por el Ayuntamiento de Zaragoza y erigido en la calle de la Independencia con motivo de la primera visita oficial del rey Alfonso XIII. Fue el segundo de los tres arcos instalados, y contâ”œâ”‚ con el diseâ”œâ–’o del arquitecto municipal Ricardo Magdalena en el estilo neogâ”œâ”‚tico al gusto de la â”œآ®poca con detalles ornamentales vegetales inequâ”œآ،vocamente modernistas, destacando por su rareza el parabâ”œâ”‚lico arco central inspirado en Gaudâ”œآ،. Destaca el leâ”œâ”‚n del escudo zaragozano adosado a los pilares que soportan el arco, y en el centro, algunos de los tradicionales sâ”œآ،mbolos del escudo de Aragâ”œâ”‚n. Al fondo, el arco de la Real Maestranza ubicado junto a la plaza de la Constituciâ”œâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65149500, -0.88178100, '0101000020E61000005F7EA7C98C37ECBFF6402B3064D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50803721857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50803721857.webp', 'https://www.flickr.com/photos/zaragozaantigua/50803721857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21356, 'Plaza de la Constituciâ”œâ”‚n 1900', 'Invernal escena capturada en la plaza de la Constituciâ”œâ”‚n posiblemente durante los denominados "dâ”œآ،as del rey" en los que se conmemoraba de forma oficial el enlace en Madrid del rey Alfonso XII con la infanta Mâ”¬آ¬ de las Mercedes de Orleans el 23 de enero de 1878. Las celebraciones castrenses incluâ”œآ،an el despliegue de bandas de mâ”œâ•‘sica de la guarniciâ”œâ”‚n en espacios como esta plaza, donde interpretaban mâ”œâ•‘sicas que pretendâ”œآ،an amenizar a paseantes y pâ”œâ•‘blico. Por ello, en la imagen aparecen algunos militares de la guarniciâ”œâ”‚n vistiendo sus trajes de gala en esta esquina occidental de la plaza con el tramo alto del Coso, mezclados en una turbamulta donde destacan unos cuantos pardales que rodean lo que parecerâ”œآ،a algâ”œâ•‘n tipo de espectâ”œأ­culo callejero del que destaca una anciana subida en una silla portando un recipiente. Por contraste, resulta curiosa la presencia, a la izquierda y justo donde la esquina, de un cartel publicitario del establecimiento de Electroterapia e Hidroterapia del especialista A. Claver sito en la calle de Valencia (esquina con la calle de Canfranc) donde se trataban "segâ”œâ•‘n la ciencia" las enfermedades del sistema nervioso. Al fondo, fachada del inmueble del nâ”œâ•‘mero 31 del Coso propiedad de Cecilio Gasca que unos aâ”œâ–’os despuâ”œآ®s serâ”œآ،a profundamente remodelada con proyecto del arquitecto Josâ”œآ® de Yarza Echenique. En â”œآ®l destaca la presencia de la Academia de Comercio de Fernando Lâ”œâ”‚pez Toral, la gran Sastrerâ”œآ،a de Francisco Pâ”œآ®rez y el tradicional establecimiento de lustrar y charolar el calzado antes de las celebraciones sociales. A la izquierda de este inmueble, leve vista de la fachada de la que fuera originalmente gran casa de Coloma sita en el nâ”œâ•‘mero 29 del Coso.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54781828524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54781828524.webp', 'https://www.flickr.com/photos/zaragozaantigua/54781828524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21377, 'Diputaciâ”œâ”‚n Provincial c.1910', 'Fototipia Thomas. c.1910. "Diputaciâ”œâ”‚n Provincial". Imagen de la plaza de la Constituciâ”œâ”‚n, con el original edificio de la DPZ. A su izquierda, el edificio esquinero de la plaza, con el "Cafâ”œآ® Suizo" en sus bajos. A su derecha, el edificio esquinero con el Coso. Ambos edificios serâ”œأ­n reformados unos aâ”œâ–’os despuâ”œآ®s, como le sucederâ”œأ­ a la sede de la DPZ. Fuente: www.el-trastero.eu/caddie/images/Zaragoza Capital-017.webp', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65217500, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF68226C787AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15737374610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15737374610.webp', 'https://www.flickr.com/photos/zaragozaantigua/15737374610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21395, 'Pl. de la Constituciâ”œâ”‚n 1913', 'Quiosco del Toni en la plaza de la Constituciâ”œâ”‚n. Al fondo, arranque del Coso Alto, con la sucursal del Banco Hispano Americano en la antigua Casa de las Balsas. A la derecha, vista parcial del inmueble del Coso nâ”¬â•‘ 33. Fuente visual: Foto Lorenzo Almarza, en Archivo de la Diputaciâ”œâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65252700, -0.88122400, '0101000020E6100000E4688EACFC32ECBFE560360186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21286830268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21286830268.webp', 'https://www.flickr.com/photos/zaragozaantigua/21286830268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21514, 'Vista de Zaragoza c.1920', 'Casino Mercantil y Agrâ”œآ،cola. Ca.1920. Decoraciâ”œâ”‚n del interior del nuevo Casino Mercantil y Agrâ”œآ،cola inspirada en la moda Regionalista y Costumbrista del momento. En la imagen, una vista sublimada de la ciudad desde el Cabezo Cortado, uno de los parajes naturales mâ”œأ­s frecuentados entonces para capturar buenas imâ”œأ­genes panorâ”œأ­micas de la ciudad. La lâ”œآ،nea de torres de la urbe medieval, como idealizado espacio de encuentro entre el cielo y un suelo que, de puro dorado, dan ganas de sisarlo.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65270400, -0.88135300, '0101000020E61000005A68E7340B34ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738628767.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738628767.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738628767/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21533, 'Coso Alto 1925', 'El Coso Alto, Lucien Roisin. Vista del Coso Alto de Zaragoza, desde el palacio de Sâ”œأ­stago (izquierda, ocupado por el Banco Espaâ”œâ–’ol de Crâ”œآ®dito) hasta su principio, al fondo, donde se ve el colegio de los Escolapios en construcciâ”œâ”‚n. Fuente: "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œآ،as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19471297663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19471297663.webp', 'https://www.flickr.com/photos/zaragozaantigua/19471297663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21586, 'Pl. de la Constituciâ”œâ”‚n c.1920', 'Obras en la confluencia de la plaza de la Constituciâ”œâ”‚n con el Coso Alto. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24786999242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24786999242.webp', 'https://www.flickr.com/photos/zaragozaantigua/24786999242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21634, 'Casco Viejo 1925', 'Imagen capturada desde la recrecida altura del inmueble del nâ”¬â•‘ 1 de la plaza de la Constituciâ”œâ”‚n, esquinero con el Coso Alto, que permite esta vista con orientaciâ”œâ”‚n norteâ”œâ–’a de los tejados del Casco Viejo que cierra el templo del Pilar. En primer tâ”œآ®rmino, luminosa terraza y palomar (a la izquierda) que culminaba de llamativa forma el modernista Centro Mercantil, Industrial y Agrâ”œآ،cola, en el inmueble del nâ”¬â•‘ 29 del Coso Alto.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65273700, -0.88128800, '0101000020E6100000936E4BE48233ECBFD0F1D1E28CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49183083221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49183083221.webp', 'https://www.flickr.com/photos/zaragozaantigua/49183083221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21641, 'Plaza de la Constituciâ”œâ”‚n c.1923', 'Imagen capturada en la plaza de la Constituciâ”œâ”‚n y centrada en la abarrotada terraza del cafâ”œآ® Gambrinus, con ingreso a la derecha. Fue en la dâ”œآ®cada de los aâ”œâ–’os 80 del siglo XIX cuando en Zaragoza se fue adoptando la costumbre europea de instalar veladores en la calle como prolongaciâ”œâ”‚n de los cafâ”œآ®s durante los meses de tiempo primaveral y veraniego.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65242400, -0.88145900, '0101000020E6100000C4793881E934ECBF11902FA182D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51115437863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51115437863.webp', 'https://www.flickr.com/photos/zaragozaantigua/51115437863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22182, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica 1956', 'Imagen capturada, posiblemente desde la altura del bloque de viviendas del nâ”¬â•‘ 1 de la plaza Emperador Carlos V, con interesante vista del entorno de la Feria de Muestras, el emboque al parque de Buenavista, y el paseo de Isabel la Catâ”œâ”‚lica, con la residencia Sanitaria Josâ”œآ® Antonio, y el Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œآ®rfanos e Hijos del Magisterio. Al otro lado del paseo, el convento de Jerusalâ”œآ®n, y la obra de urbanizaciâ”œâ”‚n asociada a la construcciâ”œâ”‚n del campo municipal de La Romareda. Una unidad de la lâ”œآ،nea 11 del tranvâ”œآ،a se encamina hacia la plaza de Espaâ”œâ–’a, a punto de cruzarse con el tendido de la lâ”œآ،nea 15, o Casablanca. Fuente visual: postal de Garcâ”œآ،a Garrabella, en www.todocoleccion.net/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63751000, -0.89841300, '0101000020E6100000D3A3A99ECCBFECBFBD6F7CED99D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31940417572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31940417572.webp', 'https://www.flickr.com/photos/zaragozaantigua/31940417572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21678, 'Pl. de Espaâ”œâ–’a 1939', 'Imagen capturada en el plaza de Espaâ”œâ–’a poco antes de la salida a primeras horas de la maâ”œâ–’ana de la I Vuelta Ciclista a Aragâ”œâ”‚n, organizada por el periâ”œâ”‚dico "Amanecer" y que con 34 corredores cubriâ”œâ”‚ siete etapas desde el 5 al 11 de octubre de 1939. Esta primera etapa se disputâ”œâ”‚ entre Zaragoza y Teruel. Los corredores llevan en el "maillot" publicidad de bicicletas "Râ”œأ­faga", proclamada por la publicidad de la â”œآ®poca como "La campeâ”œâ”‚n (sic) de Aragâ”œâ”‚n", porque "Râ”œأ­faga no corre...vuela", y accesible "De venta en los principales garajes (sic) de Espaâ”œâ–’a". En este posado encontramos, desde la izquierda, al ciclista ejeano Martâ”œآ،n Abadâ”œآ،a Cativiela, alias "Piriro"; al vizcaâ”œآ،no Federico Ezquerra Alonso; al bilbilitano de adopciâ”œâ”‚n Benito Cabestrero Rodrâ”œآ،guez; al aragonâ”œآ®s Josâ”œآ® Lahoz Trol, conocido como "el Leâ”œâ”‚n de Marâ”œآ،a" pues aunque naciâ”œâ”‚ en Azuara era marihuervano de adopciâ”œâ”‚n; el catalâ”œأ­n Mariano Caâ”œâ–’ardo Lacasta y el gallego Delio Rodrâ”œآ،guez Barros a la derecha. De fondo y a la izquierda, el Cafâ”œآ® Gambrinus, y casi ya haciendo esquina con el Coso, La Joyita, y Bombonerâ”œآ،a Murga. En el centro de la imagen, el edificio sede de la aseguradora La Patria Hispana, la sucursal del Banco de Bilbao y el Estudio Fotogrâ”œأ­fico Skogler.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65223200, -0.88128200, '0101000020E61000000BB6114F7633ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14853150812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14853150812.webp', 'https://www.flickr.com/photos/zaragozaantigua/14853150812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21693, 'P.â”¬â•‘ de la Independencia 1931', 'Carrozas pasando por delante del bar restaurante La Maravilla, en el paseo de la Independencia, en direcciâ”œâ”‚n a la plaza de la Constituciâ”œâ”‚n, durante las fiestas del Pilar del primer aâ”œâ–’o de la Segunda Repâ”œâ•‘blica. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œآ،o Ebro y el siglo XX".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65158400, -0.88130400, '0101000020E6100000FFAF3A72A433ECBF664CC11A67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15086553182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15086553182.webp', 'https://www.flickr.com/photos/zaragozaantigua/15086553182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21694, 'Pl. de la Constituciâ”œâ”‚n 1930', 'La Sublevaciâ”œâ”‚n de Jaca de diciembre de 1930 fue un pronunciamiento militar republicano contra el râ”œآ®gimen de la Restauraciâ”œâ”‚n monâ”œأ­rquica de Alfonso XIII, cuando el general Dâ”œأ­maso Berenguer era presidente del Gobierno. Tras la declaraciâ”œâ”‚n del Estado de Guerra, fue militarmente desbaratada y fusilados sus cabecillas, los capitanes Fermâ”œآ،n Galâ”œأ­n Rodrâ”œآ،guez y â”œأ¼ngel Garcâ”œآ،a Hernâ”œأ­ndez. En Zaragoza tuvo lugar el acuartelamiento de los regimientos de infanterâ”œآ،a Infante, Aragâ”œâ”‚n y Gerona, y los de caballerâ”œآ،a Castillejos y Lanceros del Rey. Por ella transitaron, camino de Jaca, fuerzas de la Guardia Civil y los batallones Saboya, Lanzarote, Reus y Estella del ejâ”œآ®rcito. Ademâ”œأ­s, parejas de la Guardia Civil, Seguridad e Infanterâ”œآ،a patrullaron calles y accesos, y custodiaron edificios oficiales como en la imagen, donde un retâ”œآ®n de guardiaciviles a caballo guarda el edificio de la Diputaciâ”œâ”‚n Provincial en la plaza de la Constituciâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15147164159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15147164159.webp', 'https://www.flickr.com/photos/zaragozaantigua/15147164159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21706, 'Pl. de Espaâ”œâ–’a 1938', 'En otro de sus paseos por la ciudad, un miembro de la alemana Legiâ”œâ”‚n Câ”œâ”‚ndor captura una instantâ”œأ­nea ciudadana recurrente, en este caso, una imagen parcial de la reciâ”œآ®n denominada "plaza de Espaâ”œâ–’a". El aâ”œâ–’o anterior, 1937, "II aâ”œâ–’o triunfal", se cambiâ”œâ”‚ el nombre de la plaza, de "Constituciâ”œâ”‚n" (para quâ”œآ®), a "Espaâ”œâ–’a", como reza la placa instalada en la fachada de la DPZ (que perdura), en "recuerdo perenne de su lealtad a la Patria y de su amor a la ciudad con motivo del glorioso Alzamiento Nacional contra el comunismo". Se trata de la esquina de la plaza con el Coso Alto, con la sede de Radio Zaragoza allâ”œآ، ubicada. A la izquierda, el edificio de la DPZ.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65270400, -0.88135300, '0101000020E61000005A68E7340B34ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16000268962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16000268962.webp', 'https://www.flickr.com/photos/zaragozaantigua/16000268962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21720, 'Pl. de la Constituciâ”œâ”‚n 1930', 'Foto Gaspar. Vista de la plaza de la Constituciâ”œâ”‚n. Preside la imagen el edificio de Miguel â”œأ¼ngel Navarro esquina con el paseo de la Independencia, que estuvo en pie con ese aspecto entre 1916 y 1940. A su derecha, la Diputaciâ”œâ”‚n Provincial. Fuente: La Esfera, 29 de noviembre de 1930.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20041643101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20041643101.webp', 'https://www.flickr.com/photos/zaragozaantigua/20041643101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21730, 'Limpiabotas aâ”œâ–’os 30', 'Varios limpiabotas aprovechan la sombra de los pilares de los porches del paseo de la Independencia para hacer su trabajo. Al fondo, la plaza de la Constituciâ”œâ”‚n. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65171000, -0.88170700, '0101000020E6100000CCEF3499F136ECBFF33CB83B6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21219972713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21219972713.webp', 'https://www.flickr.com/photos/zaragozaantigua/21219972713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21753, 'Pl. de la Constituciâ”œâ”‚n 1930', 'Vista del edificio del paseo de la Independencia 2, construido por Miguel â”œأ¼ngel Navarro en 1916 (reformado por el mismo arquitecto en 1940); y de la sede de la Diputaciâ”œâ”‚n Provincial de Zaragoza, en la plaza de la Constituciâ”œâ”‚n 2, levantado en 1858 segâ”œâ•‘n proyecto de Pedro Martâ”œآ،nez Sangrâ”œâ”‚s (remodelado por Teodoro Râ”œآ،os entre 1945 y 1952). El tranvâ”œآ،a pertenece a la lâ”œآ،nea 5 (Torrero). Fuente visual: Colecciâ”œâ”‚n Francisco Boisset.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22231235892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22231235892.webp', 'https://www.flickr.com/photos/zaragozaantigua/22231235892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21768, 'Vista de Zaragoza 1930', 'Desde las alturas del Casino Mercantil, una composiciâ”œâ”‚n de tejados del casco antiguo, que se extienden hacia varias de las torres de la ciudad. A la izquierda, la iglesia parroquial de San Felipe, el torreâ”œâ”‚n de Fortea y la iglesia de Santa Isabel de Portugal. En el centro, la basâ”œآ،lica del Pilar. Hacia la derecha, la torre y cimborrio de la Seo, y de San Nicolâ”œأ­s, San Juan y San Pedro, San Gil y la Magdalena. Composiciâ”œâ”‚n inâ”œآ®dita, democrâ”œأ­tica, cientâ”œآ،fica y popular, generada en los laboratorios del', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65313700, -0.88142800, '0101000020E610000003EB387EA834ECBF5E6743FE99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22623001473.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22623001473.webp', 'https://www.flickr.com/photos/zaragozaantigua/22623001473/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21778, 'Coso Alto 1932', 'Coso Alto hacia las calles Escuelas Pâ”œآ،as y Cerdâ”œأ­n. A la derecha, el Hotel Oriente. Hacia la izquierda, Arco de San Roque de acceso a la plaza del mismo nombre. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22952151090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22952151090.webp', 'https://www.flickr.com/photos/zaragozaantigua/22952151090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21794, 'P.â”¬â•‘ de la Independencia 1931', 'Foto: Miguel Marâ”œآ،n Chivite. Durante las fiestas del Pilar de 1931 se celebrâ”œâ”‚ una "cabalgata artâ”œآ،stica", una de cuyas carrozas representaba a "las mujeres aragonesas". Su remate recuerda el del escudo de la reciâ”œآ®n estrenada Segunda Repâ”œâ•‘blica Espaâ”œâ–’ola. La foto ofrece una vista de los pares del paseo de la Independencia, desde su esquina con la plaza de la Constituciâ”œâ”‚n. Fuente: Archivo ABC.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65185400, -0.88136400, '0101000020E610000054E57B462234ECBF26E2ADF36FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24746410491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24746410491.webp', 'https://www.flickr.com/photos/zaragozaantigua/24746410491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21818, 'P.â”¬â•‘ de la Independencia 1930', 'Imagen capturada desde cierta altura, de un sector de la plaza de la Constituciâ”œâ”‚n, y del arranque del antiguo paseo de la Independencia, cuando decâ”œآ،an que se parecâ”œآ،a a la parisina "rue du Rivoli", sobre todo por su fachada occidental (a la derecha). Una unidad tranviaria de la serie 50 de la lâ”œآ،nea "Torrero", da la vuelta para recomenzar el servicio hacia el sur de la ciudad. Fuente visual: www.delcampe.es', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65134900, -0.88165300, '0101000020E610000000732D5A8036ECBF23A46E675FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31385763036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31385763036.webp', 'https://www.flickr.com/photos/zaragozaantigua/31385763036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21825, 'Pl. de la Constituciâ”œâ”‚n 1930', 'Imagen parcial de la balconada de la antigua Diputaciâ”œâ”‚n Provincial, capturada como muestra de los efectos de la entrada en vigor del Real Decreto que "recuperaba" las diputaciones provinciales, suprimidas durante la dictadura del general Primo de Rivera. Ahora, durante la dictadura del general Dâ”œأ­maso Berenguer, buscando remozar el tambaleante râ”œآ®gimen que seguâ”œآ،a encabezado por el rey Alfonso XIII, fue derogada la disposiciâ”œâ”‚n que derogâ”œâ”‚ las diputaciones. Como consecuencia simbâ”œâ”‚lica, la fotografâ”œآ،a recoge la nueva presencia compartida de la enseâ”œâ–’a nacional, la bicolor de la izquierda, y la tradicional de la Diputaciâ”œâ”‚n de Zaragoza, la blanca cruzada con asta roja de la derecha. Sobre ambas, el râ”œâ”‚tulo identificativo de la plaza de la Constituciâ”œâ”‚n, que fue mantenido desde 1923 aunque no hubiera tal. Tras el 18 de julio de 1936, otro gallo negro nos cantarâ”œآ،a. Fuente visual: Miguel Marâ”œآ،n Chivite, periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65222100, -0.88155800, '0101000020E61000008FDE701FB935ECBFD8614CFA7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32530850206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32530850206.webp', 'https://www.flickr.com/photos/zaragozaantigua/32530850206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21831, 'P.â”¬â•‘ de la Independencia 1931', 'Foto: Miguel Marâ”œآ،n Chivite. Imagen publicada en junio de 1931 del paseo de la Independencia desde la plaza de la Constituciâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65202700, -0.88148900, '0101000020E61000006E14596B2835ECBFF38DE89E75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33363377341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33363377341.webp', 'https://www.flickr.com/photos/zaragozaantigua/33363377341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21835, 'Pl. de la Constituciâ”œâ”‚n c.1930', 'Imagen capturada en el antiguo paseo de la Independencia desde el punto de vista de un peatâ”œâ”‚n, con el fondo de la inmediata plaza de la Constituciâ”œâ”‚n y la fachada del Coso. Bien por el efecto de un reciente chaparrâ”œâ”‚n, o un manguerazo, el firme del andador central del paseo, entre acacias, bancos y quioscos, parece reflectante bajo la tibia luz del atardecer. Fuente visual: foto Juan Mora Insa, AMZ.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65179700, -0.88150400, '0101000020E6100000C36169E04735ECBFC25087156ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34119630603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34119630603.webp', 'https://www.flickr.com/photos/zaragozaantigua/34119630603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22075, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores c.1955', 'Imagen del exterior del antiguo Colegio Pompiliano de las Escolapias en el Paseo de los Ruiseâ”œâ–’ores 28. Se instalâ”œâ”‚ allâ”œآ، en 1922 en un edificio de nueva planta, dedicado a la Segunda Enseâ”œâ–’anza del "Colegio Calasanz", tambiâ”œآ®n de las Escolapias. En 1965-68 este Colegio fue objeto de una importante reforma, tanto en su aspecto exterior, como en su estructura, y adquiriâ”œâ”‚ su apariencia actual, despersonalizada, asâ”œآ®ptica. Sigue siendo un colegio privado financiado pâ”œâ•‘blicamente, es decir, concertado.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63611700, -0.88986000, '0101000020E61000000B98C0ADBB79ECBFFEB627486CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15555677327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15555677327.webp', 'https://www.flickr.com/photos/zaragozaantigua/15555677327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21885, 'Plaza de la Constituciâ”œâ”‚n 1936', 'Imagen capturada desde la leve altura de las escaleras de ingreso al antiguo edificio de la Diputaciâ”œâ”‚n Provincial sito en la plaza de la Constituciâ”œâ”‚n, y centrada en los restos de un aviâ”œâ”‚n biplano Vickers Vildebeest de las Fuerzas Aâ”œآ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola exhibido como trofeo de guerra por los nacionalistas sublevados. Aunque originalmente este aeroplano fue destinado a funciones de ataque naval, las necesidades de guerra obligaron a su uso como bombardero de ataque terrestre, en este caso en el frente de Aragâ”œâ”‚n. Al fondo, tramo edilicio del Coso recayente a la plaza entre el inmueble del nâ”¬â•‘ 33 y el nâ”¬â•‘ 39, en la embocadura de la calle de los Mâ”œأ­rtires, donde destaca el toldo del Cafâ”œآ® Oriental. En los bajos del nâ”¬â•‘ 35 destaca el râ”œâ”‚tulo del Cafâ”œآ® Royalty. La fachada del nâ”¬â•‘ 33 aparece todavâ”œآ،a sin la parafernalia de sâ”œآ،mbolos que lo identificarâ”œآ،an luego como sede provincial de Falange.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65243200, -0.88124500, '0101000020E6100000C16ED8B62833ECBF936E4BE482D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49624253307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49624253307.webp', 'https://www.flickr.com/photos/zaragozaantigua/49624253307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21889, 'Plaza de la Constituciâ”œâ”‚n 1936', 'Imagen centrada en los restos de un aviâ”œâ”‚n biplano Vickers Vildebeest de las Fuerzas Aâ”œآ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola exhibido como trofeo de guerra por los nacionalistas sublevados en un acto de propaganda y para elevar la moral de la parroquia que asiste al evento. El fondo escâ”œآ®nico viene definido por la decimonâ”œâ”‚nica fachada de la Diputaciâ”œâ”‚n Provincial, a la izquierda, y el inmueble del nâ”¬â•‘ 62-64 del Coso Alto, en cuyos bajos destaca el toldo de la terraza del Cafâ”œآ® Gambrinus.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65223200, -0.88144800, '0101000020E6100000CAFCA36FD234ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49685999638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49685999638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49685999638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21899, 'Plaza de la Constituciâ”œâ”‚n 1936', 'Desde la altura del estudio de Foto Skogler, vista en la plaza de la Constituciâ”œâ”‚n del desfile organizado con motivo de la celebraciâ”œâ”‚n del tercer aniversario de la fundaciâ”œâ”‚n de Falange en el Teatro de la Comedia de Madrid. Ademâ”œأ­s de falangistas de toda la regiâ”œâ”‚n, acudieron otros varios miles desde Logroâ”œâ–’o hasta alcanzar unos "cincuenta mil hombres, soldados de la nueva Espaâ”œâ–’a que se estâ”œأ­ forjando" (sic). En la imagen abren el desfile unos "flechas", niâ”œâ–’os entre 11 y 15 aâ”œâ–’os de la organizaciâ”œâ”‚n juvenil falangista, que dirigen la marcha hacia el tramo alto del Coso. Al fondo y en el paseo de la Independencia destaca la decimonâ”œâ”‚nica fachada del convento de Jerusalâ”œآ®n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65228000, -0.88130900, '0101000020E6100000717495EEAE33ECBFDDEA39E97DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51229924080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51229924080.webp', 'https://www.flickr.com/photos/zaragozaantigua/51229924080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21923, 'Plaza de la Constituciâ”œâ”‚n 1936', 'Imagen centrada en los restos del accidentado tren de aterrizaje de un aviâ”œâ”‚n biplano Vickers Vildebeest de las Fuerzas Aâ”œآ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola derribado en Torremocha de Jiloca (Teruel) a finales del mes de julio por los nacionalistas sublevados en armas contra la Repâ”œâ•‘blica. Posan en la instantâ”œأ­nea elementos de la organizaciâ”œâ”‚n local parapolicial Acciâ”œâ”‚n Ciudadana ante el fondo escâ”œآ®nico del inmueble del nâ”¬â•‘ 33 del Coso Alto, que pronto serâ”œآ،a habilitado como sede provincial de Falange. Este aeroplano fue exhibido en el entorno urbano ante la Diputaciâ”œâ”‚n Provincial como trofeo de guerra y "con este motivo se registraron escenas y manifestaciones de exaltaciâ”œâ”‚n patriâ”œâ”‚tica y vivas entusiâ”œأ­sticos a Espaâ”œâ–’a, al Ejâ”œآ®rcito espaâ”œâ–’ol y a las milicias movilizadas que colaboraban en este movimiento salvador de la Patria", tal y como se registraba en la prensa de la â”œآ®poca.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55041300276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55041300276.webp', 'https://www.flickr.com/photos/zaragozaantigua/55041300276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22007, 'Pl. de Espaâ”œâ–’a 1941', 'Imagen capturada junto a los evacuatorios ubicados al principio del andador central del paseo de la Independencia con vista parcial de la plaza de Espaâ”œâ–’a (de la Constituciâ”œâ”‚n antes de julio de 1936) y el arranque de la calle de Don Jaime I (al fondo). De izquierda a derecha, tres esquineras y referenciales entidades bancarias copan la visual: el Banco Zaragozano, el Banco de Espaâ”œâ–’a y el Banco de Vizcaya. Fuente visual: foto Luker, en www.todocoleccion.net', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65170500, -0.88139400, '0101000020E6100000FE7F9C306134ECBFE1D1C6116BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38808957215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38808957215.webp', 'https://www.flickr.com/photos/zaragozaantigua/38808957215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22020, 'Vista c.1940', 'Imagen capturada desde la altura del Centro Mercantil, Industrial y Agrâ”œآ،cola y orientada hacia el noroeste, con vista en primer tâ”œآ®rmino de la calle de Alfonso I, donde destaca el â”œأ­guila que culmina los homâ”œâ”‚nimos grandes almacenes, a la izquierda. Hacia el fondo y la derecha emergen la torre de la iglesia de San Felipe y Santiago el Menor, el Torreâ”œâ”‚n Fortea y la câ”œâ•‘pula y torres de la iglesia de Santa Isabel de Portugal.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65360300, -0.88162000, '0101000020E610000011FC6F253B36ECBFA3C85A43A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49894909547.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49894909547.webp', 'https://www.flickr.com/photos/zaragozaantigua/49894909547/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22138, 'Plaza Espaâ”œâ–’a 1951', 'Foto: Joan Miquel i Quintilla. Plaza de Espaâ”œâ–’a, con el Monumento a los Mâ”œأ­rtires y el inicio del paseo de la Independencia al fondo. Preside la imagen el edificio del Banco Hispano Americano, en el nâ”œâ•‘mero 2 del paseo, obra de Miguel â”œأ¼ngel Navarro de 1916 y remodelado por â”œآ®l mismo en 1940. Fuente: barcelonafotoantic.com/', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65192600, -0.88138500, '0101000020E610000031EBC5504E34ECBFC0B4A84F72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24756570536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24756570536.webp', 'https://www.flickr.com/photos/zaragozaantigua/24756570536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22241, 'P.â”¬â•‘ de la Independencia 1953', 'Nocturna imagen de la luminosa fachada de la sucursal del Banco de Vizcaya sita en el paseo de la Independencia nâ”¬â•‘ 4. Fundado en 1901, este banco inaugurâ”œâ”‚ sucursal en la ciudad en 1930 justo enfrente a esta ubicaciâ”œâ”‚n. En la imagen, el paseo presenta su tradicional pavimentado de cuando el boulevar central arbolado caracterizaba su aspecto. Entre las piedras del suelo refulgen las vâ”œآ،as del tranvâ”œآ،a. Hacia la izquierda, ingreso a la calle del Requetâ”œآ® Aragonâ”œآ®s. Flechas y yugos y una jaculatoria al Jefe del estado aparecen pintadas en los pilares que soportan los porches del paseo.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65190300, -0.88163100, '0101000020E61000000C7904375236ECBF0795B88E71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51022538653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51022538653.webp', 'https://www.flickr.com/photos/zaragozaantigua/51022538653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22115, 'Marifâ”œآ® de Triana 1956', 'Foto: Miguel Marâ”œآ،n Chivite. La etapa 11 de la Vuelta Ciclista a Espaâ”œâ–’a de 1956 (Tâ”œأ­rrega-Zaragoza), celebrada el 6 de mayo de 1956, dio como vencedor al belga Rik Van Steenbergen (abajo). Arriba a la derecha, la cantante Marifâ”œآ® de Triana (1936-2013), que actuaba esos dâ”œآ،as en el Teatro Principal, le entrega el ramo de flores de rigor en el lugar de la meta, el parque Primo de Rivera. Fuente: Heraldo de Aragâ”œâ”‚n.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63438400, -0.89427000, '0101000020E6100000CB67791EDC9DECBF868DB27E33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22339736449.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22339736449.webp', 'https://www.flickr.com/photos/zaragozaantigua/22339736449/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22242, 'Calle de Alfonso I, 1953', 'Imagen centrada en los bajos comerciales que flanquean el ingreso al inmueble del nâ”¬â•‘ 12 de la calle de Alfonso I. Asâ”œآ،, a la izquierda, la tienda de Calzados Briz, y a la derecha la sucursal urbana nâ”¬â•‘ 1 del Banco Popular Espaâ”œâ–’ol. Esta entidad habâ”œآ،a sido fundada en 1926 con el nombre de "Banco Popular de los Previsores del Porvenir", que conservâ”œâ”‚ hasta que en 1947 adquiriâ”œâ”‚ la denominaciâ”œâ”‚n que luce en la fachada. Sobre ella, el estudio fotogrâ”œأ­fico de los Coyne. En 2017 este banco fue comprado por el Santander al precio de 1 euro, y tras un largo proceso de integraciâ”œâ”‚n operativa, en 2019 desapareciâ”œâ”‚ su marca corporativa.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65337000, -0.88171700, '0101000020E6100000AF78EA910637ECBF0118CFA0A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51024022221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51024022221.webp', 'https://www.flickr.com/photos/zaragozaantigua/51024022221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22474, 'Plaza de San Roque c.1965', 'Imagen a cierta altura, capturada posiblemente desde el Hotel Oriente, del entorno de la plaza de San Roque y el arranque de la calle del Teniente Coronel Valenzuela, donde la amplia zona de aparcamiento en baterâ”œآ،a evidencia la absoluta necesidad, para ese objeto, del ensanche acometido en esta calle en 1942, que supuso, entre otros, el derribo del barroco arco de San Roque. Fuente visual: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65281400, -0.88163300, '0101000020E61000003961C2685636ECBF7B2FBE688FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33860972440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33860972440.webp', 'https://www.flickr.com/photos/zaragozaantigua/33860972440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22531, 'Pl. de Espaâ”œâ–’a 1973', 'La plaza de Espaâ”œâ–’a seguâ”œآ،a siendo el centro neurâ”œأ­lgico de la ciudad, si bien a medida que terminaba el siglo esa centralidad se iba desplazando hacia la plaza de Basilio Paraâ”œآ،so. En la imagen y al fondo, tramo del Coso entre la calle de los Mâ”œأ­rtires y la de Don Jaime I, donde se destacan los grandes anuncios comerciales luminosos establecidos sobre los tejados. El Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria, aislado de su entorno, aparece como hito visual referente de la rotonda automovilâ”œآ،stica de la plaza. En primer tâ”œآ®rmino y a la izquierda, coexistencia pacâ”œآ،fica de dos medios de transporte pâ”œâ•‘blicos: el tranvâ”œآ،a nâ”¬â•‘ 112 de la lâ”œآ،nea 5. Venecia-Delicias, y el autobâ”œâ•‘s urbano, en este caso microbâ”œâ•‘s de la lâ”œآ،nea Miraflores-Plaza del Pilar, poco antes de que el segundo destronara al primero, con el inestimable fomento polâ”œآ،tico del Ayuntamiento.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65204800, -0.88133600, '0101000020E6100000D732198EE733ECBF0BB6114F76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14729125847.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14729125847.webp', 'https://www.flickr.com/photos/zaragozaantigua/14729125847/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22750, 'Pl. de Espaâ”œâ–’a 1972', 'Imagen de la tranviaria composiciâ”œâ”‚n M113+R113 de la lâ”œآ،nea 5 "corta" (tras la supresiâ”œâ”‚n del tramo de Delicias) Plaza Espaâ”œâ–’a-Venecia, encaminada hacia el elevado sur de la ciudad. Ni corta, ni perezosa, esta lâ”œآ،nea no llegarâ”œآ،a a ver la Copa Mundial de Fâ”œâ•‘tbol celebrada en la Repâ”œâ•‘blica Federal de Alemania en 1974: las molestias que ocasionaba a la circulaciâ”œâ”‚n rodada parecâ”œآ،an insoportables, como la imagen bien ilustra. Al fondo, la vistosa fachada del Coso con sus comerciales de neâ”œâ”‚n. Fuente visual: www.flickr.com/photos/jhm0284/5812528283/in/album-7215763...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32594356565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32594356565.webp', 'https://www.flickr.com/photos/zaragozaantigua/32594356565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23072, 'Coso 2007', 'Fuente: Wikipedia, 2007. Aspecto del tramo del Coso Alto con el palacio de Sâ”œأ­stago y la densa circulaciâ”œâ”‚n rodada anterior a la implantaciâ”œâ”‚n del tranvâ”œآ،a en 2011.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012274978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012274978.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012274978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23094, 'Palacio de Sâ”œأ­stago 2000', 'Aspecto de la fachada sur del palacio de Sâ”œأ­stago de Zaragoza, antes de su restauraciâ”œâ”‚n entre 2001 y 2003. Actualmente esta ubicaciâ”œâ”‚n es un patio interior de la Diputaciâ”œâ”‚n Provincial de Zaragoza. La hilera de ventanas superior alberga las dependencias de la Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico. Fuente: "Restauraciâ”œâ”‚n del patrimonio histâ”œâ”‚rico en la provincia de Zaragoza", Diputaciâ”œâ”‚n de Zaragoza, 2003.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65247300, -0.88168500, '0101000020E6100000D8F50B76C336ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21500598541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21500598541.webp', 'https://www.flickr.com/photos/zaragozaantigua/21500598541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23131, 'Coso alto 2004', 'En 1967 fue fundada la Caja Rural Comarcal de Calatayud, en esa localidad, por Salvador Ibarra Franco. En 1970 la entidad cambiâ”œâ”‚ su denominaciâ”œâ”‚n por Caja Rural del Jalâ”œâ”‚n ("Cajalâ”œâ”‚n") Sociedad Cooperativa de Credito, y en 1979 trasladâ”œâ”‚ su sede social a Zaragoza, en el paseo de la Independencia nâ”¬â•‘ 25. En 2004, y tras dos aâ”œâ–’os de costosa rehabilitaciâ”œâ”‚n integral, inaugurâ”œâ”‚ su nueva sede en el antiguo inmueble del Casino Mercantil, en el nâ”¬â•‘ 29 del Coso. Durante los actos de presentaciâ”œâ”‚n de la flamante sede, desde la entidad se dijo que con ello "Nos vestimos de largo, es nuestra mayorâ”œآ،a de edad tras haber adecuado previamente la estructura interna". En 2011, tras el proceso de fusiâ”œâ”‚n con Multicaja, Cajalâ”œâ”‚n se integrâ”œâ”‚ en la Nueva Caja Rural de Aragâ”œâ”‚n Sociedad Cooperativa de Crâ”œآ®dito, que desde enero de 2012 opera bajo la denominaciâ”œâ”‚n Bantierra Cooperativa de Credito. En la imagen, fachada del nâ”¬â•‘ 29 del Coso alto, como nueva sede central de Cajalâ”œâ”‚n. En primer plano, el Coso como coto vedado para uso de la circulaciâ”œâ”‚n rodada. Fuente visual: es.wikipedia.org', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65270400, -0.88132100, '0101000020E610000082E50819C833ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31636805394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31636805394.webp', 'https://www.flickr.com/photos/zaragozaantigua/31636805394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
