INSERT INTO public.photos VALUES (23292, 'Calle de Alfonso I c.1964', 'Foto: Ediciones Sicilia. Imagen nocturna de la Calle Alfonso I de Zaragoza engalanada. Fuente: rafaelcastillejo.com', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20523509138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20523509138.webp', 'https://www.flickr.com/photos/zaragozaantigua/20523509138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23293, 'Calle de Alfonso I 1958', 'Foto: Ediciones Sicilia. Colecciâ”œâ”‚n de â”œأ¼ngel Ruiz. Vista nocturna de la calle Alfonso I de Zaragoza en octubre de 1958. Fuente: rafaelcastillejo.com', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20685122166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20685122166.webp', 'https://www.flickr.com/photos/zaragozaantigua/20685122166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23294, 'Calle de Alfonso I 1908', 'Paso de la comparsa de gigantes y cabezudos en direcciâ”œâ”‚n hacia el Coso Alto, a la altura de la calle del Cuatro de Agosto. El engalanamiento es debido a las celebraciones del centenario de los sitios. Fuente visual: Archivo Julio Requejo (DARA-AHPZ).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21092411081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21092411081.webp', 'https://www.flickr.com/photos/zaragozaantigua/21092411081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23297, 'Calle de Alfonso I c.1900', 'Postal editada por la "Fototipia Hauser y Menet" (Madrid), con imagen de la calle Alfonso I en el turno de paseo de "no elegantes" de clase baja. Un vehâ”œآ،culo a propulsiâ”œâ”‚n de sangre, estacionado sin complejos. A la derecha, el entronque con la calle del Cuatro de Agosto. Fuente visual: www.delcampe.net/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65351700, -0.88169400, '0101000020E6100000A48AE255D636ECBFA530EF71A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22845537949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22845537949.webp', 'https://www.flickr.com/photos/zaragozaantigua/22845537949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22213, 'Parque Grande 1955', 'Imagen capturada desde la altura del Cabezo de Buenavista y orientada hacia el ingreso al Parque de Primo de Rivera desde el puente del Trece de Septiembre. Centran la imagen, entre la foresta, las instalaciones del Jardâ”œآ،n Botâ”œأ­nico. A la izquierda, emerge el destacado volumen de la Residencia Sanitaria Josâ”œآ® Antonio. A su lado y hacia el fondo, el despejado panorama de torres agrâ”œآ،colas entre el Polâ”œآ،gono Gran Vâ”œآ،a y la carretera de Valencia. A la derecha, la torre de la Feria de Muestras y el cuartel de Palafox, tras el que la vista todavâ”œآ،a alcanza hasta los pabellones del Hospital Psiquiâ”œأ­trico Nuestra Seâ”œâ–’ora del Pilar. Fuente visual: AMZ', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63548000, -0.89649900, '0101000020E6100000CDB1BCAB1EB0ECBF8CA19C6857D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46027854615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46027854615.webp', 'https://www.flickr.com/photos/zaragozaantigua/46027854615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23301, 'Calle del Blasâ”œâ”‚n Aragonâ”œآ®s 1966', 'Imagen capturada desde el cruce de la calle del Cuatro de Agosto (de izquierda a derecha) con la antigua calle del Peso, luego redenominada "Blasâ”œâ”‚n Aragonâ”œآ®s", que conduce, al fondo, a la antigua plaza del Carbâ”œâ”‚n, luego de Sas. La calle del Peso, hacâ”œآ،a referencia a la ubicaciâ”œâ”‚n del "Peso del Rey" utilizado para la distribuciâ”œâ”‚n al por menor del carbâ”œâ”‚n vegetal como elemento imprescindible para los hogares, como combustible para la cocina, y para proporcionar calor al hogar en invierno. En la manzana de la derecha, entre la calle del Cuatro de Agosto, y Estâ”œآ®banes, se abre el denominado "Pasaje de los Giles", nombre dado en el siglo XIX al enorme espacio compuesto desde el siglo XVI por el patio de la Casa de los Estâ”œآ®banes, por una galerâ”œآ،a, y un patio posterior ajardinado en las traseras de la casa. Este espacio fue muy reformado en el siglo XIX por sus nuevos propietarios, los comerciantes y hermanos Garcâ”œآ،a Gil, con intervenciones diseâ”œâ–’adas por Julio Bravo, y Ricardo Magdalena. En los aâ”œâ–’os 50 del pasado siglo, Teodoro Râ”œآ،os consolida la cimentaciâ”œâ”‚n. A comienzos del presente siglo XXI, ha sido "rehabilitado" integralmente. En la imagen, en la acera de los pares de la calle Blasâ”œâ”‚n Aragonâ”œآ®s, andamios que anuncian el principio del fin de la esquinera casona palaciega de los barones de La Linde, y su sustituciâ”œâ”‚n por nuevos y modernos edificios mâ”œأ­s acordes a los tiempos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65339700, -0.88125400, '0101000020E61000008E03AF963B33ECBFFA264D83A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24131226424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24131226424.webp', 'https://www.flickr.com/photos/zaragozaantigua/24131226424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23307, 'Calle de Alfonso I 1874', 'Vista de la calle de Alfonso I. Fuente: Anselmo Marâ”œآ،a Coyne Barreras, probable copia de imagen de Mariano Jâ”œâ•‘dez y Ortiz. Colecciâ”œâ”‚n Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65351700, -0.88169400, '0101000020E6100000A48AE255D636ECBFA530EF71A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28553354656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28553354656.webp', 'https://www.flickr.com/photos/zaragozaantigua/28553354656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23502, 'Coso Alto 1930', '"Calle del Coso". A la izquierda, el Palacio de Sâ”œأ­stago y el edificio del antiguo Banco de Aragâ”œâ”‚n. A la derecha, la entrada a la calle Alfonso. Al fondo, el chaflâ”œأ­n de Escolapios.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65278500, -0.88156700, '0101000020E61000005C7347FFCB35ECBFE12879758ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061161651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061161651.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061161651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23505, 'Casino Mercantil 1937', 'El sâ”œأ­bado 30 de enero de 1937 tuvo lugar "una fiesta brillante" en el Centro Mercantil, Industrial y Agrâ”œآ،cola de la ciudad. La Colonia Alemana y la organizaciâ”œâ”‚n local del NSDAP (National Sozialistische Deutsche Arbeiterpartei, Partido Nacionalsocialista Alemâ”œأ­n de los Trabajadores) prepararon la conmemoraciâ”œâ”‚n del aniversario 4 del ascenso al poder de Adolf Hitler como su "Fuhrer". El "Salâ”œâ”‚n Restaurant" del Centro fue engalanado al efecto con profusiâ”œâ”‚n de banderas nacionalistas, y una tribuna especial para los discursos, con un retrato de Hitler, la svâ”œأ­stica, flores, y un atril. Hubo una "concurrencia numerosâ”œآ،sima", entre la que destacaba el vicepresidente de la DPZ (sr. Mola), un representante del Ayuntamiento (sr. Julve), dos representantes de Falange (sres. Mâ”œâ•‘gica, y Gil Sastre), el câ”œâ”‚nsul italiano en la ciudad (sr. Ricardo Piccio), y las directivas de la Colonia Alemana, y del NSDAP local. Hubo discursos por parte del Sr. Julve, del Sr. Piccio, y del jefe local del NSDAP, sr. Fleischmann, que loaron a Espaâ”œâ–’a, Portugal, Italia, Alemania, y el Japâ”œâ”‚n, y exaltaron a Adolfo Hitler como "caudillo sin ejemplo en la historia del mundo". Hubo aplausos, recuerdo a sus muertos, saludos fascistas, himnos nacionalistas, y desfile de banderas. Las crâ”œâ”‚nicas no lo reflejan, pero algo de beber y de comer habrâ”œآ،a. Al terminar el acto, la Colonia Alemana agradeciâ”œâ”‚ a la direcciâ”œâ”‚n del Centro Mercantil la cesiâ”œâ”‚n del local. En la imagen, el jefe local en Zaragoza del NSDAP, sr. Fleischmann, durante su intervenciâ”œâ”‚n, detrâ”œأ­s de Hitler y la svâ”œأ­stica, y delante de los portaestandartes con las enseâ”œâ–’as de la Alemania nazi, la Espaâ”œâ–’a franquista, la Italia fascista, y de Falange. 14 aâ”œâ–’os antes, un tal Albert Einstein estuvo en la ciudad, muy cerca del lugar de autos. Era otro tipo de alemâ”œأ­n, que cumplâ”œآ،a tambiâ”œآ®n 4 aâ”œâ–’os, pero de exilio.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65295400, -0.88154500, '0101000020E610000068791EDC9D35ECBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893988667.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893988667.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893988667/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23509, 'Coso Alto 1889', 'Saragosse. Rue del Coso. J. Lâ”œآ®vy et Cie, 1889. Vista del Coso Alto desde la plaza de la Constituciâ”œâ”‚n de Zaragoza. En la dâ”œآ®cada de los sesenta del siglo XIX, la transformaciâ”œâ”‚n del antiguo Trenque de Ximeno Gordo, luego calle del Trenque, en la nueva "calle de Don Alfonso I" supuso, entre otras cosas, la obligada renumeraciâ”œâ”‚n de los azulejos del Coso, y la adecuaciâ”œâ”‚n de los edificios esquineros. Con esta monumental imagen nos podemos acercar al estado de los edificios entre la nueva calle Alfonso, y la plaza de la Constituciâ”œâ”‚n, en sus nâ”œâ•‘meros impares (los de la derecha). Asâ”œآ،, la Casa de Eusebio Molins, remodelada luego en formas modernistas; una casa de alquiler donde residiâ”œâ”‚ Francisco de Goya en 1780-81; la vecina casa de Martâ”œآ،n Zapater (â”œآ،ntimo de Goya), con andamios para adecuarla, entre otras cosas, a importante tienda de telas; la antigua Casa de Juan Coloma, antes de ser convertida en Centro Mercantil, Industrial y Agrâ”œآ،cola; la casa de los marqueses de Nibbiano, con andamios altos para remodelarla en profundidad y darle una mano de decoraciâ”œâ”‚n historicista que perdurarâ”œأ­ hasta que acabe en manos del Banco de Bilbao; inmediata, otra casa de los Nibbiano que fue pasando de manos en manos hasta recaer en 1936 como sede provincial de la Falange, y en los aâ”œâ–’os cincuenta terminar como propiedad del Banco Vitalicio de Espaâ”œâ–’a. Fuente visual: Zaragoza en la mirada ajena. Cortes de Aragâ”œâ”‚n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18614224408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18614224408.webp', 'https://www.flickr.com/photos/zaragozaantigua/18614224408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23515, 'Coso Alto 2011', 'Foto: Oliver Duch. Imagen testigo de la llegada de los raâ”œآ،les del tranvâ”œآ،a en septiembre de 2011, durante las obras de la segunda fase de la lâ”œآ،nea 1, en su recorrido por el Coso Alto. Al fondo, la plaza de Espaâ”œâ–’a. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65276600, -0.88151300, '0101000020E610000090F63FC05A35ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26562082199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26562082199.webp', 'https://www.flickr.com/photos/zaragozaantigua/26562082199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23516, 'Coso Alto 1861', 'Vista de la calle del Coso en su tramo Alto, tomada desde la plaza de la Constituciâ”œâ”‚n. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28504316721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28504316721.webp', 'https://www.flickr.com/photos/zaragozaantigua/28504316721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23524, 'Coso Alto 2012', '"Iris del Coso Alto", â”œâ”‚leo sobre lienzo, Eduardo Laborda, 2012. La compaâ”œâ–’era del pintor, Iris Lâ”œأ­zaro, aparece a la derecha en el Casino Mercantil, frente al palacio de Sâ”œأ­stago. Mâ”œأ­s allâ”œأ­, las sucesivas sedes del Banco de Aragâ”œâ”‚n y el edificio La Adriâ”œأ­tica. Sobre el firme, obras de la segunda fase de la lâ”œآ،nea 1 del tranvâ”œآ،a. Fuente: Heraldo de Aragâ”œâ”‚n.', 2012, 2012, 2012, 'Siglo XXI', 'CENTRO', 41.65275800, -0.88152400, '0101000020E61000008A73D4D17135ECBFE719FB928DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39160609620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39160609620.webp', 'https://www.flickr.com/photos/zaragozaantigua/39160609620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23531, 'Centro Mercantil 1937', 'Imagen capturada en el salâ”œâ”‚n-comedor del Centro Mercantil, Industrial y Agrâ”œآ،cola en el Coso durante la conmemoraciâ”œâ”‚n del cuarto aniversario de la "toma del poder por el Fuhrer Adolfo Hitler" (30 de enero de 1933), acto organizado por el grupo local del "Partido Obrero Nacional-Socialista Alemâ”œأ­n" (NSDAP). Centra la escena la tribuna levantada al fondo del comedor y decorada con profusiâ”œâ”‚n de motivos vegetales, la esvâ”œأ­stica y un retrato del "Fuhrer", durante la intervenciâ”œâ”‚n del jefe local del NSDAP, seâ”œâ–’or Fleischmann uniformado con la preceptiva camisa parda. El testero de la tribuna presenta una gran bandera con la cruz gamada ante la que forman portaestandartes con las banderas nacionalista espaâ”œâ–’ola, de Falange, la italiana y la alemana. Entre las autoridades asistentes destacâ”œâ”‚ el gestor municipal Julve en representaciâ”œâ”‚n del alcalde; los diputados provinciales Rivas y Mola; el jefe de la Segunda lâ”œآ،nea de Falange, Mâ”œâ•‘gica ; los câ”œâ”‚nsules de Italia y Portugal; toda la colonia alemana y una representaciâ”œâ”‚n de la colonia italiana. Hubo discursos de Julve, del câ”œâ”‚nsul italiano, representantes de la colonia alemana y del NSDAP, Fleischmann, que loaron a Espaâ”œâ–’a, Portugal, Italia, Alemania y aun el Japâ”œâ”‚n, exaltaron a Adolfo Hitler como "caudillo sin ejemplo en la historia del mundo", y auguraron un destino paralelo entre Alemania y Espaâ”œâ–’a: "el de su gloria y su grandeza". Ademâ”œأ­s hubo "poesâ”œآ،as y cantos de carâ”œأ­cter patriâ”œâ”‚tico"; una orquesta interpretâ”œâ”‚ piezas de Beethoven y Wagner, ademâ”œأ­s de los himnos alemâ”œأ­n e italiano y el de Falange; aplausos, recuerdo a sus muertos, saludos fascistas, desfile de banderas, despedida y cierre.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65304200, -0.88130900, '0101000020E6100000717495EEAE33ECBF0C7558E196D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/