INSERT INTO public.photos VALUES (22423, 'Parque Primo de RIvera c.1968', 'Fuentes del paseo de San Sebastiâ”œأ­n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27320115622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27320115622.webp', 'https://www.flickr.com/photos/zaragozaantigua/27320115622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24358, 'San Juan de los Panetes 1933', 'Archivo ABC. "Incendio de la iglesia de San Juan de los Panetes (Zaragoza) el 19 de diciembre de 1933. Poco antes habâ”œآ،a sido declarado monumento nacional."', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65753200, -0.88120800, '0101000020E610000078279F1EDB32ECBF680932022AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14977800452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14977800452.webp', 'https://www.flickr.com/photos/zaragozaantigua/14977800452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23532, 'Coso Alto 2005', 'Imagen capturada el 8 de noviembre de 2005 durante la presentaciâ”œâ”‚n en Zaragoza de "El vano ayer", novela ganadora de la decimocuarta ediciâ”œâ”‚n del premio literario hispanoamericano "Râ”œâ”‚mulo Gallegos" el aâ”œâ–’o 2005. Centra la escena el sevillano Isaac Rosa Camacho, autor de la novela, flanqueado a nuestra derecha por el historiador Javier Rodrigo Sâ”œأ­nchez, que ese mismo aâ”œâ–’o vio publicado su trabajo titulado "Cautivos. Campos de concentraciâ”œâ”‚n en la Espaâ”œâ–’a franquista (1936-1947)"; y a nuestra izquierda por el tambiâ”œآ®n historiador Manuel Ballarâ”œآ،n Aured, que en 2004 vio publicado su trabajo "La razâ”œâ”‚n en marcha. Crâ”œâ”‚nica del Frente Popular de Zaragoza". La novela presentada, "una durâ”œآ،sima requisitoria al franquismo, a la brutalidad de su sistema policial, a la corrupciâ”œâ”‚n moral que implantâ”œâ”‚ en el paâ”œآ،s", venâ”œآ،a acompaâ”œâ–’ada de cierta polâ”œآ®mica sensacionalista a cuenta de que el jurado de este premio tenâ”œآ،a connotaciones "bolivarianas" y "chavistas", y a que al autor "se le habâ”œآ،a oâ”œآ،do hablar a favor de la Revoluciâ”œâ”‚n Cubana acompaâ”œâ–’ado sospechosamente de castristas". Casualmente, esta presentaciâ”œâ”‚n tuvo como escenario la FNAC de Zaragoza, que en los aâ”œâ–’os treinta del pasado siglo XX era una horchaterâ”œآ،a propiedad de Mas que tras el 18-19 de julio de 1936 vio câ”œâ”‚mo el piso situado sobre ella se convertâ”œآ،a en una "checa" u "oficina de investigaciâ”œâ”‚n" de sospechosos de no simpatizar con la sediciâ”œâ”‚n armada contra la Repâ”œâ•‘blica espaâ”œâ–’ola.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65300200, -0.88176000, '0101000020E610000081785DBF6037ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52748029423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52748029423.webp', 'https://www.flickr.com/photos/zaragozaantigua/52748029423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23988, '14 de abril de 1931', 'Plaza de la Constituciâ”œâ”‚n de Zaragoza, martes 14 de abril de 1931. Proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica espaâ”œâ–’ola y celebraciâ”œâ”‚n consiguiente. Al fondo a la derecha, la Diputaciâ”œâ”‚n Provincial. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15858894161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15858894161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15858894161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24001, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Imagen capturada durante la callejera celebraciâ”œâ”‚n ciudadana de la llegada de la Segunda Repâ”œâ•‘blica, en la plaza de la Constituciâ”œâ”‚n, un luminoso 14 de abril. Animoso grupo de trabajadoras del corte y confecciâ”œâ”‚n, en primera lâ”œآ،nea celebrativa. Al fondo, el clasicista edificio de la Diputaciâ”œâ”‚n Provincial inaugurado en 1858, con su caracterâ”œآ،stico remate en semicircular frontâ”œâ”‚n. Fuente visual: Foto Martâ”œآ،nez ("Mundo Grâ”œأ­fico", Madrid).', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21881708770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21881708770.webp', 'https://www.flickr.com/photos/zaragozaantigua/21881708770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24004, 'P.â”¬â•‘ de la Independencia 1975', 'â”¬آ½Espaâ”œâ–’oles... Franco ha muerto. El hombre de excepciâ”œâ”‚n que ante Dios y ante la Historia asumiâ”œâ”‚ la inmensa responsabilidad del mâ”œأ­s exigente y sacrificado servicio a Espaâ”œâ–’a ha entregado su vida, quemada dâ”œآ،a a dâ”œآ،a, hora a hora, en el cumplimiento de una misiâ”œâ”‚n trascendental. Yo sâ”œآ® que en estos momentos mi voz llegarâ”œأ­ a vuestros hogares entrecortada y confundida por el murmullo de vuestros sollozos y de vuestras plegarias. Es natural; es el llanto de Espaâ”œâ–’a, que siente como nunca la angustia infinita de su orfandad. Es la hora del dolor y de la tristeza...â”¬â•— (Principio de la compungida y peripatâ”œآ®tica intervenciâ”œâ”‚n televisiva de Carlos Arias Navarro, Presidente del Gobierno, anunciando la muerte del Jefe del Estado, el 20-N-1975). Inmediatamente, fueron suspendidos todos los demâ”œأ­s espectâ”œأ­culos pâ”œâ•‘blicos hasta el domingo siguiente, dâ”œآ،a 23. Con este, suficiente. Las clases (escolares) quedaron suspendidas una semana, hasta el dâ”œآ،a 27. Una bendiciâ”œâ”‚n para las familias. La capilla ardiente del finado fue encendida en el Palacio de Oriente al dâ”œآ،a siguiente, dâ”œآ،a 21. Dos dâ”œآ،as despuâ”œآ®s, el sâ”œأ­bado 22, fue proclamado sucesor como Jefe del Estado el delfâ”œآ،n Juan Carlos de Borbâ”œâ”‚n. El domingo 23, Franco fue inhumado en el "Valle de los Caâ”œآ،dos". En la imagen, lectura de la muerte de Franco recogida en el local diario "El Noticiero", en los porches del paseo de la Independencia, en la primera de las varias ediciones de ese dâ”œآ،a que vivimos peligrosamente.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65171000, -0.88170700, '0101000020E6100000CCEF3499F136ECBFF33CB83B6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23545954464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23545954464.webp', 'https://www.flickr.co