INSERT INTO public.photos VALUES (24929, 'Piscina Parque Grande 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1968. Desde mediados de los aâ”œâ–’os 60, varios parques de la ciudad fueron dotados de piscinas para la chavalerâ”œآ،a. Tâ”œآ،o Jorge, Bruil, y Parque Grande aâ”œâ–’adâ”œآ،an en verano el atractivo del agua y la diversiâ”œâ”‚n bajo la canâ”œآ،cula, que en Zaragoza no es cualquier cosa. No tenâ”œآ،an recinto que las delimitara, estaban abiertas a todo el mundo, y solâ”œآ،an llenarse hasta parecer pobladas por piojos mojados. Pero era lo que habâ”œآ،a. Ya en los aâ”œâ–’os 80, la nuevas polâ”œآ،ticas municipales asumieron constituir una red de piscinas municipales en los barrios, incluyendo los rurales, que alcanzan la cifra de 22. Aquellas viejas piscinas sesenteras fueron clausuradas por motivos de salubridad y seguridad. La imagen recoge la piscina del Parque Grande, ubicada justo entre el râ”œآ،o Huerva y el actual Paseo de los Plâ”œأ­tanos, del que se podâ”œآ،a acceder por la rampa de la imagen, al fondo, a la derecha.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63214300, -0.89796800, '0101000020E61000004B581B6327BCECBF9AB2D30FEAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14859093063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14859093063.webp', 'https://www.flickr.com/photos/zaragozaantigua/14859093063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24013, 'Pl. de Espaâ”œâ–’a 1966', 'El obligatorio Referâ”œآ®ndum (habâ”œآ،a que firmar certificados de participaciâ”œâ”‚n) celebrado el 14 de diciembre de 1966, sometâ”œآ،a a sufragio la "Ley Orgâ”œأ­nica del Estado", apenas unos leves retoques cosmâ”œآ®ticos de algunas instituciones del Râ”œآ®gimen, pero eran tan buenos y populares que recibieron el 95,06% de votos favorables. El 4,94% restante, entre votos nulos, y negativos. El referâ”œآ®ndum fue antecedido de una campaâ”œâ–’a de propaganda donde se identificaba el "Sâ”œآ،" con "un futuro de paz y progreso", con "patria, progreso, justicia, pan, bienestar, seguridad, porvenir, desarrollo y paz". El "Sâ”œآ،" era tambiâ”œآ®n un "Sâ”œآ، a Franco", porque "Franco triunfâ”œâ”‚ en el pasado, asegura el presente, y promete el futuro". Como los menores de 21 aâ”œâ–’os no tenâ”œآ،an derecho a votar, se recomendaba que, ya que "Tus hijos menores no votan, Tâ”œâ•‘, sâ”œآ،. Asegâ”œâ•‘rales un futuro de paz y de progreso en el referâ”œآ®ndum nacional". Un peculiar y castizo fenâ”œâ”‚meno de democracia, progreso y participaciâ”œâ”‚n, tan singular como los arcoiris de Plutâ”œâ”‚n. En la imagen, vista de la plaza de Espaâ”œâ–’a en las inmediaciones a las urnas de la Diputaciâ”œâ”‚n Provincial, con nutridas filas de ardorosos y concienciados participantes en el referâ”œآ®ndum, porque â”¬â”گquiâ”œآ®n no se atreverâ”œآ،a a votar por el bienestar de sus hijos, y el de Franco mismo? Entre las pelâ”œآ،culas del momento, en la cartelera de la ciudad, "Divorcio a la italiana", porque a la espaâ”œâ–’ola, imposible.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24189394985.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24189394985.webp', 'https://www.flickr.com/photos/zaragozaantigua/24189394985/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24015, 'P.â”¬â•‘ de la Independencia 2003', 'La convocatoria de manifestaciones contra la invasiâ”œâ”‚n de Irak por parte de los Estados Unidos se considera la primera movilizaciâ”œâ”‚n global de la historia. Las mâ”œأ­s numerosas se produjeron el 15 de febrero de 2003, con el lema de "â”¬أ­No a la guerra!". Un ejemplo es la de Zaragoza, que congregâ”œâ”‚ a una muchedumbre en el paseo de la Independencia y aledaâ”œâ–’os. El 20 de marzo de 2003 comenzâ”œâ”‚, sin embargo, la invasiâ”œâ”‚n prevista, con el apoyo del Gobierno de Espaâ”œâ–’a. Fuente: Agencia EFE.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65174600, -0.88174200, '0101000020E6100000E84EB0FF3A37ECBF40A6B5696CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24303954079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24303954079.webp', 'https://www.flickr.com/photos/zaragozaantigua/24303954079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24049, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Aspecto de la plaza de la Constituciâ”œâ”‚n, con la Diputaciâ”œâ”‚n Provincial al fondo, durante las celebraciones de la tarde del 14 de abril de 1931, dâ”œآ،a de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65210100, -0.88122500, '0101000020E6100000FB5C6DC5FE32ECBF2E58AA0B78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31125852943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31125852943.webp', 'https://www.flickr.com/photos/zaragozaantigua/31125852943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24063, 'Plaza de Espaâ”œâ–’a 1966', 'Como anuncia el cartelâ”œâ”‚n del Argensola, "A reir tocan". En primer tâ”œآ®rmino, exultantes mozos celebran haber sido sorteados para el servicio militar obligatorio, con sonoro acompaâ”œâ–’amiento musical de guitarra y palmas, y alcohol de literal garrafâ”œâ”‚n. A la derecha, carteles con algunos candidatos a las "elecciones" municipales por el tercio de representantes sindicales celebradas con notable â”œآ®xito de participaciâ”œâ”‚n (algo mâ”œأ­s del 30%), siendo electos los seâ”œâ–’ores Emilio Parra Gasque, Joaquâ”œآ،n Liarte Alpuente, Josâ”œآ® Rodrigo Liarte, y Alfonso Solâ”œأ­ns Serrano. Paul Newman, caracterizado como "Harper", ojiplâ”œأ­tico ante el panorama. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65196100, -0.88140400, '0101000020E6100000E10852297634ECBF3CA2427573D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796513701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796513701.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796513701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24065, 'Fiesta del Trabajo 1931', 'El primer 1 de mayo desde la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica fue celebrado a lo grande en Zaragoza, con una manifestaciâ”œâ”‚n que discurriâ”œâ”‚ entre la plaza de la Libertad y el Gobierno Civil y contâ”œâ”‚ con la asistencia calculada por la prensa de la â”œآ®poca en unas 30.000 personas y que por ello fue considerada la mâ”œأ­s numerosa de aquellos tiempos. En la imagen del paseo de la Independencia la captura fotogrâ”œأ­fica se centra en el cortejo encabezado con la pancarta de la Agrupaciâ”œâ”‚n Socialista de Zaragoza, donde destaca el sâ”œآ،mbolo del PSOE del yunque y la pluma. Al fondo, plaza de la Constituciâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65158000, -0.88152600, '0101000020E6100000B85B92037635ECBF255D33F966D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33106148790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33106148790.webp', 'https://www.flickr.com/photos/zaragozaantigua/33106148790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24100, 'Plaza de Espaâ”œâ–’a c.1937', 'Insâ”œâ”‚lita imagen capturada en la nueva plaza de Espaâ”œâ–’a cuando seâ”œâ–’oras y seâ”œâ–’oritas procesionando desde el Coso Alto ingresan a ella ante la sede provincial de Falange Espaâ”œâ–’ola de las JONS portando banderas nacionalistas y una pancarta entusiasta con el partido â”œâ•‘nico. Al fondo y a la izquierda, el inmueble del nâ”¬â•‘ 31 del Coso, que entre otros negocios acogâ”œآ،a a la sede central del Banco de Bilbao, la compaâ”œâ–’â”œآ،a aseguradora La Patria Hispana, y el estudio fotogrâ”œأ­fico "Skogler" regentado por â”œأ¼ngel Cortâ”œآ®s Gracia, que en la imagen aparece con camisa blanca asomado a la izquierda del balcâ”œâ”‚n. A la derecha, el inmueble del nâ”¬â•‘ 33 que, propiedad del Banco Vitalicio, acogâ”œآ،a la sede de Falange, ademâ”œأ­s de la joyerâ”œآ،a de A. Agueras y el despacho del corredor de comercio S. Hernâ”œأ­ndez.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51175302112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51175302112.webp', 'https://www.flickr.com/photos/zaragozaantigua/51175302112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
